// ============================================================
// StepWise Editor - Advanced Annotation System
// Tools: Select (drag/move/recolor), Circle, Rect, Arrow,
//        Pen, Pixel Eraser, Object Eraser, Undo
// ============================================================

// Default company branding (hardcoded — users can still change these)
var DEFAULT_LOGO = "data:image/png;base64,";
var DEFAULT_BRAND_NAME = "Ultimate Online Mastery";
var DEFAULT_BRAND_COLOR = "#d4a017";
var DEFAULT_ACCENT_COLOR = "#8b6914";

var state = {
  title: "How to Configure Your Dashboard", subtitle: "",
  steps: [],
  brand: { name: DEFAULT_BRAND_NAME, primaryColor: DEFAULT_BRAND_COLOR, accentColor: DEFAULT_ACCENT_COLOR, logo: DEFAULT_LOGO },
  activeStepId: null
};

var pendingScreenshotStepId = null;
var annoState = {};
var currentTool = "circle";
var currentColor = "#ef4444";
var currentSize = 3;
window._blurIntensity = 10;
window._stepnumPrefix = "Step-";
window._stepnumCounter = {}; // per-step counters

// TTS Playback state
var ttsAudio = null;
var ttsPlayingSid = null;
var ttsPlayAllMode = false;
var ttsPlayAllIndex = 0;
var ttsAudioCache = {}; // cache generated audio per step to avoid re-calling API

// ============================================================
// PUBLISH CONFIG — Your VPS Publish API
// ============================================================
var PUBLISH_API_URL = "https://app.heychatmate.com/stepwise-api";
var PUBLISH_SECRET = ""; // Will be loaded from chrome.storage settings

// ============================================================
// INIT
// ============================================================

var projectFileHandle = null; // Stored for quick save
var editorRecording = false;
var recPollInterval = null;
var lastKnownStepCount = 0;

document.addEventListener("DOMContentLoaded", function() {
  document.getElementById("addStepBtn").addEventListener("click", addManualStep);
  document.getElementById("dropZone").addEventListener("click", function() { document.getElementById("jsonFileInput").click(); });
  document.getElementById("dropZone").addEventListener("dragover", function(e) { e.preventDefault(); e.currentTarget.classList.add("dragover"); });
  document.getElementById("dropZone").addEventListener("dragleave", function(e) { e.currentTarget.classList.remove("dragover"); });
  document.getElementById("dropZone").addEventListener("drop", handleDrop);
  document.getElementById("loadDemoBtn").addEventListener("click", loadDemoData);
  document.getElementById("brandName").addEventListener("input", updateBrand);
  document.getElementById("brandColor").addEventListener("input", updateBrand);
  document.getElementById("accentColor").addEventListener("input", updateBrand);
  document.getElementById("brandColorHex").addEventListener("input", function() { if (/^#[0-9a-fA-F]{6}$/.test(this.value)) { document.getElementById("brandColor").value = this.value; updateBrand(); } });
  document.getElementById("accentColorHex").addEventListener("input", function() { if (/^#[0-9a-fA-F]{6}$/.test(this.value)) { document.getElementById("accentColor").value = this.value; updateBrand(); } });
  document.getElementById("logoUpload").addEventListener("click", function() { document.getElementById("logoFileInput").click(); });
  document.getElementById("exportHtmlBtn").addEventListener("click", exportHTML);
  document.getElementById("exportPdfBtn").addEventListener("click", exportPDF);
  document.getElementById("exportJsonBtn").addEventListener("click", exportJSONFile);
  document.getElementById("previewBtn").addEventListener("click", previewDoc);
  document.getElementById("shareBtn").addEventListener("click", shareDoc);
  document.getElementById("copyShareBtn").addEventListener("click", function() {
    var inp = document.getElementById("shareUrlInput");
    inp.select(); navigator.clipboard.writeText(inp.value).then(function() { showToast("Link copied!"); });
  });
  document.getElementById("aiAllBtn").addEventListener("click", generateAllDescriptions);
  document.getElementById("ttsPlayAllBtn").addEventListener("click", ttsPlayAll);
  document.getElementById("generateVideoBtn").addEventListener("click", startVideoGeneration);
  document.getElementById("videoCancelBtn").addEventListener("click", cancelVideoGeneration);
  document.getElementById("ttsVoiceSelect").addEventListener("change", function() {
    // Clear cache when voice changes so new voice is used
    ttsAudioCache = {};
  });
  document.getElementById("jsonFileInput").addEventListener("change", handleJSONImport);
  document.getElementById("logoFileInput").addEventListener("change", handleLogoUpload);
  document.getElementById("screenshotFileInput").addEventListener("change", function(e) {
    var file = e.target.files[0];
    if (!file || !pendingScreenshotStepId) return;
    var reader = new FileReader();
    reader.onload = function(ev) { updateStepField(pendingScreenshotStepId, "screenshot", ev.target.result); delete annoState[pendingScreenshotStepId]; render(); };
    reader.readAsDataURL(file);
  });

  // --- Project Save/Load ---
  document.getElementById("saveProjectBtn").addEventListener("click", saveProject);
  document.getElementById("saveQuickBtn").addEventListener("click", quickSaveProject);
  document.getElementById("loadProjectBtn").addEventListener("click", loadProject);
  document.getElementById("loadProjectBtnHome").addEventListener("click", loadProject);
  document.getElementById("importJsonBtnHome").addEventListener("click", function() { document.getElementById("jsonFileInput").click(); });

  // --- Continue Recording from Editor ---
  document.getElementById("editorContinueRecBtn").addEventListener("click", editorStartRecording);
  document.getElementById("editorStopRecBtn").addEventListener("click", editorStopRecording);
  document.getElementById("editorContinueRecBtn2").addEventListener("click", editorStartRecording);
  document.getElementById("editorStopRecBtn2").addEventListener("click", editorStopRecording);
  document.getElementById("autoTitleBtn").addEventListener("click", autoGenerateTitle);

  // --- Brand settings: save on change, load on init ---
  document.getElementById("brandName").addEventListener("change", saveBrandSettings);
  document.getElementById("brandColor").addEventListener("change", saveBrandSettings);
  document.getElementById("accentColor").addEventListener("change", saveBrandSettings);
  loadBrandSettings();

  // --- Keyboard shortcut: Ctrl+S to quick save ---
  document.addEventListener("keydown", function(e) {
    if ((e.ctrlKey || e.metaKey) && e.key === "s") {
      e.preventDefault();
      if (projectFileHandle) quickSaveProject();
      else saveProject();
    }
  });

  // --- Load steps from background/storage ---
  if (typeof chrome !== "undefined" && chrome.runtime && chrome.runtime.sendMessage) {
    var storageSteps = null;
    var bgSteps = null;
    var loadCount = 0;

    function finishLoading() {
      loadCount++;
      if (loadCount < 2) return;

      var bestSteps = [];
      if (storageSteps && storageSteps.length > 0) bestSteps = storageSteps;
      if (bgSteps && bgSteps.length > bestSteps.length) bestSteps = bgSteps;

      if (bestSteps.length > 0) {
        state.steps = bestSteps;
        state.steps.forEach(function(s) { if (!s.annotations) s.annotations = []; });
        if (state.steps.length > 0) state.activeStepId = state.steps[0].id;
        lastKnownStepCount = state.steps.length;
        showEditor(); render();
        console.log("Loaded " + state.steps.length + " steps");
      }
    }

    chrome.storage.local.get(["exportData"], function(result) {
      if (result.exportData && result.exportData.steps) {
        storageSteps = result.exportData.steps;
      }
      finishLoading();
    });

    chrome.runtime.sendMessage({ action: "GET_STEPS" }, function(res) {
      if (chrome.runtime.lastError) { finishLoading(); return; }
      if (res && res.steps && res.steps.length > 0) bgSteps = res.steps;
      finishLoading();
    });

    loadShareHistory();

    // Check if already recording
    chrome.runtime.sendMessage({ action: "GET_STATUS" }, function(res) {
      if (chrome.runtime.lastError) return;
      if (res && res.isRecording) {
        editorRecording = true;
        updateRecordingUI();
        startRecordingPoll();
      }
    });
  }
});

// ============================================================
// SVG ICONS
// ============================================================

var ICONS = {
  select: '<path d="M3 3l7.07 16.97 2.51-7.39 7.39-2.51L3 3z" fill="none" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/>',
  circle: '<circle cx="12" cy="12" r="8" fill="none" stroke="currentColor" stroke-width="2"/>',
  rect: '<rect x="4" y="4" width="16" height="16" rx="2" fill="none" stroke="currentColor" stroke-width="2"/>',
  arrow: '<line x1="5" y1="19" x2="19" y2="5" stroke="currentColor" stroke-width="2"/><polyline points="12 5 19 5 19 12" fill="none" stroke="currentColor" stroke-width="2"/>',
  pen: '<path d="M17 3a2.83 2.83 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5L17 3z" fill="none" stroke="currentColor" stroke-width="2"/>',
  blur: '<rect x="3" y="3" width="18" height="18" rx="3" fill="none" stroke="currentColor" stroke-width="2" stroke-dasharray="4 2"/><line x1="7" y1="8" x2="17" y2="8" stroke="currentColor" stroke-width="2" opacity="0.3"/><line x1="7" y1="12" x2="17" y2="12" stroke="currentColor" stroke-width="2" opacity="0.3"/><line x1="7" y1="16" x2="14" y2="16" stroke="currentColor" stroke-width="2" opacity="0.3"/>',
  callout: '<rect x="2" y="2" width="14" height="10" rx="3" fill="none" stroke="currentColor" stroke-width="2"/><line x1="12" y1="12" x2="21" y2="21" stroke="currentColor" stroke-width="2"/><circle cx="21" cy="21" r="1.5" fill="currentColor"/>',
  stepnum: '<circle cx="12" cy="12" r="9" fill="none" stroke="currentColor" stroke-width="2"/><text x="12" y="16" text-anchor="middle" fill="currentColor" font-size="12" font-weight="bold">1</text>',
  pixelEraser: '<path d="M20 20H7L3 16c-.8-.8-.8-2 0-2.8L14.2 2l7.6 7.6L10.4 21" fill="none" stroke="currentColor" stroke-width="2"/><line x1="2" y1="22" x2="22" y2="22" stroke="currentColor" stroke-width="2"/>',
  objectEraser: '<path d="M20 20H7L3 16c-.8-.8-.8-2 0-2.8L14.2 2l7.6 7.6L10.4 21" fill="none" stroke="currentColor" stroke-width="2"/><circle cx="18" cy="6" r="4" fill="none" stroke="currentColor" stroke-width="1.5"/><line x1="16" y1="6" x2="20" y2="6" stroke="currentColor" stroke-width="1.5"/>',
  undo: '<polyline points="1 4 1 10 7 10" fill="none" stroke="currentColor" stroke-width="2"/><path d="M3.51 15a9 9 0 1 0 2.13-9.36L1 10" fill="none" stroke="currentColor" stroke-width="2"/>'
};

function svgIcon(name, size) {
  return '<svg width="' + (size||16) + '" height="' + (size||16) + '" viewBox="0 0 24 24" fill="none">' + ICONS[name] + '</svg>';
}

// ============================================================
// RENDERING
// ============================================================

function render() {
  renderSidebar();
  renderEditor();
  document.getElementById("totalStepCount").textContent = state.steps.length;
}

function renderSidebar() {
  var list = document.getElementById("stepsList");
  list.innerHTML = "";
  if (state.steps.length === 0) { list.innerHTML = '<div style="padding:16px;text-align:center;color:var(--text-3);font-size:11px;">No steps yet</div>'; return; }
  state.steps.forEach(function(step, i) {
    var div = document.createElement("div");
    div.className = "step-item" + (step.id === state.activeStepId ? " active" : "");
    div.innerHTML = '<div class="snum">' + (i+1) + '</div>' +
      (step.screenshot ? '<img class="sthumb" src="' + step.screenshot + '">' : '') +
      '<div class="sinfo"><div class="stitle">' + esc(step.title || "Untitled") + '</div><div class="surl">' + hostname(step.url) + '</div></div>' +
      '<div class="sactions"><button class="sa-btn mu" data-id="' + step.id + '">\u2191</button><button class="sa-btn md" data-id="' + step.id + '">\u2193</button><button class="sa-btn danger del" data-id="' + step.id + '">\u00d7</button></div>';
    div.addEventListener("click", function(e) { if (!e.target.closest(".sa-btn")) selectStep(step.id); });
    list.appendChild(div);
  });
  list.querySelectorAll(".mu").forEach(function(b) { b.addEventListener("click", function(e) { e.stopPropagation(); moveStep(b.dataset.id, -1); }); });
  list.querySelectorAll(".md").forEach(function(b) { b.addEventListener("click", function(e) { e.stopPropagation(); moveStep(b.dataset.id, 1); }); });
  list.querySelectorAll(".del").forEach(function(b) { b.addEventListener("click", function(e) { e.stopPropagation(); deleteStep(b.dataset.id); }); });
}

function renderEditor() {
  var editor = document.getElementById("stepsEditor");
  editor.innerHTML = "";
  if (state.steps.length === 0) { editor.innerHTML = '<div class="no-steps-msg"><h3>No steps yet</h3><p>Import or add steps manually</p></div>'; return; }

  state.steps.forEach(function(step, i) {
    var card = document.createElement("div");
    card.className = "step-editor" + (step.id === state.activeStepId ? " active" : "");
    card.id = "editor-" + step.id;

    var sid = step.id;
    var as = annoState[sid];
    var selectedIdx = as ? as.selectedIndex : -1;

    // Toolbar
    var tb = '<div class="anno-toolbar" data-sid="' + sid + '">';
    var tools = [
      ["select", "Select & Move"],
      ["circle", "Circle"],
      ["rect", "Rectangle"],
      ["arrow", "Arrow"],
      ["pen", "Pen"],
      ["blur", "Blur Box"],
      ["callout", "Callout"],
      ["stepnum", "Step Number"],
      ["pixelEraser", "Pixel Eraser"],
      ["objectEraser", "Object Eraser"]
    ];
    tools.forEach(function(t) {
      tb += '<button class="anno-tool' + (currentTool === t[0] ? ' active' : '') + '" data-tool="' + t[0] + '" title="' + t[1] + '">' +
        svgIcon(t[0]) + '<span class="tool-label">' + t[1] + '</span></button>';
    });
    tb += '<div class="anno-sep"></div>';
    tb += '<input type="color" class="anno-color acolor" value="' + currentColor + '" title="Color">';
    tb += '<select class="anno-size-select asize">' +
      '<option value="2"' + (currentSize===2?' selected':'') + '>Thin</option>' +
      '<option value="3"' + (currentSize===3?' selected':'') + '>Medium</option>' +
      '<option value="5"' + (currentSize===5?' selected':'') + '>Thick</option>' +
      '<option value="8"' + (currentSize===8?' selected':'') + '>Extra</option></select>';

    // Blur intensity control (only visible when blur tool active)
    tb += '<span class="blur-controls" style="display:' + (currentTool === "blur" ? "inline-flex" : "none") + ';align-items:center;gap:4px;">' +
      '<span style="font-size:10px;color:var(--text-3);">Blur:</span>' +
      '<input type="range" class="blur-intensity-slider" min="3" max="25" value="' + (window._blurIntensity || 10) + '" style="width:60px;height:16px;">' +
      '<span class="blur-val" style="font-size:10px;color:var(--text-3);min-width:22px;">' + (window._blurIntensity || 10) + 'px</span></span>';

    // Step number prefix control (only visible when stepnum tool active)
    tb += '<span class="stepnum-controls" style="display:' + (currentTool === "stepnum" ? "inline-flex" : "none") + ';align-items:center;gap:4px;">' +
      '<span style="font-size:10px;color:var(--text-3);">Prefix:</span>' +
      '<input type="text" class="stepnum-prefix-input" value="' + esc(window._stepnumPrefix || "Step-") + '" style="width:55px;font-size:11px;padding:2px 4px;background:var(--surface-2);border:1px solid var(--border);border-radius:4px;color:var(--text);">' +
      '</span>';

    tb += '<div class="anno-sep"></div>';
    tb += '<button class="anno-tool undo-btn" data-sid="' + sid + '" title="Undo">' + svgIcon("undo") + '<span class="tool-label">Undo</span></button>';
    tb += '<button class="anno-tool reset-btn" data-sid="' + sid + '" title="Reset All" style="color:#ef4444;"><svg width="16" height="16" viewBox="0 0 24 24" fill="none"><path d="M3 6h18M8 6V4a2 2 0 012-2h4a2 2 0 012 2v2M19 6l-1 14a2 2 0 01-2 2H8a2 2 0 01-2-2L5 6" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg><span class="tool-label">Reset All</span></button>';

    // Show selected object info
    if (selectedIdx >= 0 && as && as.shapes[selectedIdx]) {
      var sel = as.shapes[selectedIdx];
      tb += '<span class="selection-info">' + sel.type + ' selected <button class="deselect-btn" data-sid="' + sid + '">\u00d7</button>';
      // Edit text button for callouts
      if (sel.type === "callout") {
        tb += ' <button class="edit-callout-btn" data-sid="' + sid + '" data-idx="' + selectedIdx + '" style="margin-left:4px;padding:2px 8px;background:#8b5cf6;color:#fff;border:none;border-radius:4px;cursor:pointer;font-size:10px;font-weight:600;">Edit Text</button>';
      }
      tb += '</span>';
    }

    tb += '</div>';

    // Screenshot + canvas
    var imgHtml = '<div class="annotation-container" data-sid="' + sid + '">';
    if (step.screenshot) {
      imgHtml += '<img src="' + step.screenshot + '" data-sid="' + sid + '" class="anno-img">' +
        '<canvas class="annotation-canvas" data-sid="' + sid + '"></canvas>';
    } else {
      imgHtml += '<div class="annotation-placeholder upload-ss" data-sid="' + sid + '"><svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/><path d="M21 15l-5-5L5 21"/></svg><span style="font-size:12px;">Click to upload screenshot</span></div>';
    }
    imgHtml += '</div>';

    card.innerHTML = '<div class="step-editor-header"><div class="step-badge" style="background:' + state.brand.primaryColor + '">' + (i+1) + '</div>' +
      '<input type="text" class="step-title-input title-inp" data-sid="' + sid + '" value="' + escAttr(step.title) + '" placeholder="Step title...">' +
      '<button class="title-mic-btn mic-title-dictate" data-sid="' + sid + '" title="Dictate title">\ud83c\udfa4</button></div>' +
      '<div class="step-editor-body">' + tb + imgHtml +
      '<textarea class="step-description desc-inp" data-sid="' + sid + '" placeholder="Describe this step...">' + esc(step.description || '') + '</textarea>' +
      '<div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap;">' +
      '<button class="ai-btn ai-gen" data-sid="' + sid + '">\u26a1 AI Generate</button>' +
      '<button class="ai-btn mic-dictate" data-sid="' + sid + '">\ud83c\udfa4 Dictate</button>' +
      '<button class="ai-btn tts-play" data-sid="' + sid + '">\ud83d\udd0a Play</button></div></div>';

    card.addEventListener("click", function(e) {
      // Don't re-render when clicking editable areas
      if (e.target.closest(".anno-toolbar") || e.target.closest(".annotation-canvas") || e.target.closest(".step-description") || e.target.closest(".step-title-input") || e.target.closest(".ai-btn") || e.target.closest(".mic-dictate") || e.target.closest(".tts-play") || e.target.closest(".mic-title-dictate")) return;
      if (step.id !== state.activeStepId) selectStep(step.id);
    });
    editor.appendChild(card);
  });

  // Attach listeners
  editor.querySelectorAll(".title-inp").forEach(function(inp) { inp.addEventListener("input", function() { updateStepField(inp.dataset.sid, "title", inp.value); }); inp.addEventListener("blur", function() { renderSidebar(); }); });
  editor.querySelectorAll(".desc-inp").forEach(function(ta) { ta.addEventListener("input", function() { updateStepField(ta.dataset.sid, "description", ta.value); }); });
  editor.querySelectorAll(".upload-ss").forEach(function(d) { d.addEventListener("click", function() { uploadScreenshot(d.dataset.sid); }); });
  editor.querySelectorAll(".ai-gen").forEach(function(b) { b.addEventListener("click", function(e) { e.stopPropagation(); generateDescription(b.dataset.sid); }); });
  editor.querySelectorAll(".mic-dictate").forEach(function(b) {
    b.addEventListener("click", function(e) {
      e.stopPropagation();
      toggleDictation(b.dataset.sid, b);
    });
  });
  editor.querySelectorAll(".tts-play").forEach(function(b) {
    b.addEventListener("click", function(e) {
      e.stopPropagation();
      ttsPlayStep(b.dataset.sid, b);
    });
  });
  editor.querySelectorAll(".mic-title-dictate").forEach(function(b) {
    b.addEventListener("click", function(e) {
      e.stopPropagation();
      toggleTitleDictation(b.dataset.sid, b);
    });
  });

  // Tool buttons
  editor.querySelectorAll(".anno-tool[data-tool]").forEach(function(btn) {
    btn.addEventListener("click", function(e) {
      e.stopPropagation();
      currentTool = btn.dataset.tool;
      if (currentTool !== "select") {
        Object.keys(annoState).forEach(function(sid) { annoState[sid].selectedIndex = -1; });
      }
      document.querySelectorAll(".anno-tool[data-tool]").forEach(function(b) { b.classList.toggle("active", b.dataset.tool === currentTool); });
      // Show/hide tool-specific controls
      document.querySelectorAll(".blur-controls").forEach(function(el) { el.style.display = currentTool === "blur" ? "inline-flex" : "none"; });
      document.querySelectorAll(".stepnum-controls").forEach(function(el) { el.style.display = currentTool === "stepnum" ? "inline-flex" : "none"; });
      updateCursors();
    });
  });

  // Blur intensity slider
  editor.querySelectorAll(".blur-intensity-slider").forEach(function(sl) {
    sl.addEventListener("input", function() {
      window._blurIntensity = parseInt(sl.value);
      var valSpan = sl.parentElement.querySelector(".blur-val");
      if (valSpan) valSpan.textContent = sl.value + "px";
    });
  });

  // Step number prefix input
  editor.querySelectorAll(".stepnum-prefix-input").forEach(function(inp) {
    inp.addEventListener("input", function() {
      window._stepnumPrefix = inp.value;
    });
    inp.addEventListener("click", function(e) { e.stopPropagation(); });
  });

  editor.querySelectorAll(".acolor").forEach(function(inp) {
    inp.addEventListener("input", function() {
      currentColor = inp.value;
      // If an object is selected, update its color
      Object.keys(annoState).forEach(function(sid) {
        var as = annoState[sid];
        if (as && as.selectedIndex >= 0 && as.shapes[as.selectedIndex]) {
          as.shapes[as.selectedIndex].color = currentColor;
          saveShapes(sid);
          redrawShapes(sid);
        }
      });
    });
  });

  editor.querySelectorAll(".asize").forEach(function(sel) {
    sel.addEventListener("change", function() {
      currentSize = parseInt(sel.value);
      // If an object is selected, update its size
      Object.keys(annoState).forEach(function(sid) {
        var as = annoState[sid];
        if (as && as.selectedIndex >= 0 && as.shapes[as.selectedIndex]) {
          as.shapes[as.selectedIndex].size = currentSize;
          saveShapes(sid);
          redrawShapes(sid);
        }
      });
    });
  });

  editor.querySelectorAll(".undo-btn").forEach(function(btn) { btn.addEventListener("click", function(e) { e.stopPropagation(); undoAnnotation(btn.dataset.sid); }); });
  editor.querySelectorAll(".reset-btn").forEach(function(btn) {
    btn.addEventListener("click", function(e) {
      e.stopPropagation();
      var sid = btn.dataset.sid;
      if (!confirm("Clear ALL annotations on this step?")) return;
      var as = annoState[sid];
      if (as) {
        pushHistory(sid);
        as.shapes = [];
        as.selectedIndex = -1;
        saveShapes(sid);
        redrawShapes(sid);
        window._stepnumCounter[sid] = 0;
        showToast("All annotations cleared");
      }
    });
  });
  editor.querySelectorAll(".deselect-btn").forEach(function(btn) {
    btn.addEventListener("click", function(e) {
      e.stopPropagation();
      var as = annoState[btn.dataset.sid];
      if (as) { as.selectedIndex = -1; redrawShapes(btn.dataset.sid); render(); }
    });
  });
  editor.querySelectorAll(".edit-callout-btn").forEach(function(btn) {
    btn.addEventListener("click", function(e) {
      e.stopPropagation();
      var sid = btn.dataset.sid;
      var idx = parseInt(btn.dataset.idx);
      var as = annoState[sid];
      if (as && as.canvas) openCalloutEditor(sid, idx, as.canvas);
    });
  });

  setTimeout(initCanvases, 50);
}

function updateCursors() {
  document.querySelectorAll(".annotation-canvas").forEach(function(c) {
    if (currentTool === "select") c.style.cursor = "default";
    else if (currentTool === "objectEraser") c.style.cursor = "pointer";
    else c.style.cursor = "crosshair";
  });
}

// ============================================================
// ANNOTATION CANVAS
// ============================================================

function getAS(sid) {
  if (!annoState[sid]) {
    annoState[sid] = { shapes: [], history: [[]], historyIndex: 0, drawing: false, dragging: false, startX: 0, startY: 0, penPoints: [], selectedIndex: -1, dragOffX: 0, dragOffY: 0, canvas: null, ctx: null, imgW: 0, imgH: 0 };
  }
  return annoState[sid];
}

function initCanvases() {
  document.querySelectorAll(".annotation-canvas").forEach(function(canvas) {
    var sid = canvas.dataset.sid;
    var container = canvas.parentElement;
    var img = container.querySelector("img");
    if (!img) return;

    var setup = function() {
      var rect = img.getBoundingClientRect();
      canvas.width = rect.width;
      canvas.height = rect.height;
      canvas.style.width = rect.width + "px";
      canvas.style.height = rect.height + "px";

      var as = getAS(sid);
      as.canvas = canvas;
      as.ctx = canvas.getContext("2d");
      as.imgW = rect.width;
      as.imgH = rect.height;

      // Restore saved annotations
      var step = state.steps.find(function(s) { return s.id === sid; });
      if (step && step.annotations && step.annotations.length > 0 && as.shapes.length === 0) {
        as.shapes = step.annotations.slice();
        as.history = [[], as.shapes.slice()];
        as.historyIndex = 1;
      }

      redrawShapes(sid);
      updateCursors();

      canvas.addEventListener("mousedown", function(e) { onDown(e, sid); });
      canvas.addEventListener("mousemove", function(e) { onMove(e, sid); });
      canvas.addEventListener("mouseup", function(e) { onUp(e, sid); });
      canvas.addEventListener("mouseleave", function(e) { var as = getAS(sid); if (as.drawing || as.dragging || as.draggingArrowTip) onUp(e, sid); });

      // Double-click to edit callout text
      canvas.addEventListener("dblclick", function(e) {
        e.preventDefault(); e.stopPropagation();
        var as = getAS(sid);
        var pos = getPos(e, sid);
        for (var ci = as.shapes.length - 1; ci >= 0; ci--) {
          var sh = as.shapes[ci];
          if (sh.type === "callout" && pos.x >= sh.x && pos.x <= sh.x + sh.w && pos.y >= sh.y && pos.y <= sh.y + sh.h) {
            openCalloutEditor(sid, ci, canvas);
            break;
          }
        }
      });
    };

    if (img.complete && img.naturalWidth > 0) setup(); else img.addEventListener("load", setup);
  });
}

function getPos(e, sid) {
  var as = getAS(sid);
  if (!as.canvas) return { x: 0, y: 0 };
  var r = as.canvas.getBoundingClientRect();
  return { x: e.clientX - r.left, y: e.clientY - r.top };
}

// --- Hit Testing ---

function hitTest(shapes, x, y, threshold) {
  for (var i = shapes.length - 1; i >= 0; i--) {
    var s = shapes[i];
    if (s.type === "eraser") continue;
    var t = threshold || 8;

    if (s.type === "circle") {
      var dx = (x - s.cx) / (s.rx || 1);
      var dy = (y - s.cy) / (s.ry || 1);
      var dist = Math.sqrt(dx*dx + dy*dy);
      if (Math.abs(dist - 1) < t / Math.min(s.rx || 1, s.ry || 1) + 0.3) return i;
      if (dist < 1) return i;
    } else if (s.type === "rect") {
      if (x >= s.x - t && x <= s.x + s.w + t && y >= s.y - t && y <= s.y + s.h + t) return i;
    } else if (s.type === "arrow") {
      if (distToSegment(x, y, s.x1, s.y1, s.x2, s.y2) < t) return i;
    } else if (s.type === "pen") {
      for (var j = 1; j < s.points.length; j++) {
        if (distToSegment(x, y, s.points[j-1].x, s.points[j-1].y, s.points[j].x, s.points[j].y) < t) return i;
      }
    } else if (s.type === "blur") {
      if (x >= s.x - t && x <= s.x + s.w + t && y >= s.y - t && y <= s.y + s.h + t) return i;
    } else if (s.type === "callout") {
      // Hit on box
      if (x >= s.x - t && x <= s.x + s.w + t && y >= s.y - t && y <= s.y + s.h + t) return i;
      // Hit on arrow tip
      if (Math.sqrt(Math.pow(x - s.arrowX, 2) + Math.pow(y - s.arrowY, 2)) < 15) return i;
      // Hit on arrow line
      var edgePt = getBoxEdgePoint(s.x, s.y, s.w, s.h, s.arrowX, s.arrowY);
      if (distToSegment(x, y, edgePt.x, edgePt.y, s.arrowX, s.arrowY) < t) return i;
    } else if (s.type === "stepnum") {
      var r = s.radius || 18;
      if (Math.sqrt(Math.pow(x - s.cx, 2) + Math.pow(y - s.cy, 2)) < r + t) return i;
    }
  }
  return -1;
}

function distToSegment(px, py, x1, y1, x2, y2) {
  var dx = x2 - x1, dy = y2 - y1;
  var len2 = dx*dx + dy*dy;
  if (len2 === 0) return Math.sqrt((px-x1)*(px-x1) + (py-y1)*(py-y1));
  var t = Math.max(0, Math.min(1, ((px-x1)*dx + (py-y1)*dy) / len2));
  var projX = x1 + t*dx, projY = y1 + t*dy;
  return Math.sqrt((px-projX)*(px-projX) + (py-projY)*(py-projY));
}

// --- Get shape bounding box center ---

function getShapeCenter(s) {
  if (s.type === "circle") return { x: s.cx, y: s.cy };
  if (s.type === "rect") return { x: s.x + s.w/2, y: s.y + s.h/2 };
  if (s.type === "arrow") return { x: (s.x1+s.x2)/2, y: (s.y1+s.y2)/2 };
  if (s.type === "blur") return { x: s.x + s.w/2, y: s.y + s.h/2 };
  if (s.type === "callout") return { x: s.x + s.w/2, y: s.y + s.h/2 };
  if (s.type === "stepnum") return { x: s.cx, y: s.cy };
  if (s.type === "pen" && s.points.length > 0) {
    var sx = 0, sy = 0;
    s.points.forEach(function(p) { sx += p.x; sy += p.y; });
    return { x: sx/s.points.length, y: sy/s.points.length };
  }
  return { x: 0, y: 0 };
}

// --- Move shape by delta ---

function moveShape(s, dx, dy) {
  if (s.type === "circle") { s.cx += dx; s.cy += dy; }
  else if (s.type === "rect") { s.x += dx; s.y += dy; }
  else if (s.type === "arrow") { s.x1 += dx; s.y1 += dy; s.x2 += dx; s.y2 += dy; }
  else if (s.type === "pen") { s.points.forEach(function(p) { p.x += dx; p.y += dy; }); }
  else if (s.type === "blur") { s.x += dx; s.y += dy; }
  else if (s.type === "callout") { s.x += dx; s.y += dy; s.arrowX += dx; s.arrowY += dy; }
  else if (s.type === "stepnum") { s.cx += dx; s.cy += dy; }
}

// --- Mouse Handlers ---

function onDown(e, sid) {
  e.preventDefault(); e.stopPropagation();
  var as = getAS(sid);
  var pos = getPos(e, sid);

  if (currentTool === "select") {
    // Check if clicking callout arrow tip first
    var arrowTipHit = -1;
    for (var ai = as.shapes.length - 1; ai >= 0; ai--) {
      var sh = as.shapes[ai];
      if (sh.type === "callout" && Math.sqrt(Math.pow(pos.x - sh.arrowX, 2) + Math.pow(pos.y - sh.arrowY, 2)) < 12) {
        arrowTipHit = ai;
        break;
      }
    }

    if (arrowTipHit >= 0) {
      as.selectedIndex = arrowTipHit;
      as.draggingArrowTip = true;
      as.dragging = false;
      as.startX = pos.x;
      as.startY = pos.y;
      redrawShapes(sid);
      render();
      return;
    }

    var hitIdx = hitTest(as.shapes, pos.x, pos.y);
    if (hitIdx >= 0) {
      as.selectedIndex = hitIdx;
      as.dragging = true;
      as.draggingArrowTip = false;
      as.startX = pos.x;
      as.startY = pos.y;
      var sel = as.shapes[hitIdx];
      if (sel.color) { currentColor = sel.color; document.querySelectorAll(".acolor").forEach(function(c) { c.value = sel.color; }); }
      if (sel.size) { currentSize = sel.size; document.querySelectorAll(".asize").forEach(function(s) { s.value = String(sel.size); }); }
      redrawShapes(sid);
      render();
    } else {
      as.selectedIndex = -1;
      redrawShapes(sid);
      render();
    }
    return;
  }

  if (currentTool === "objectEraser") {
    var hitIdx = hitTest(as.shapes, pos.x, pos.y);
    if (hitIdx >= 0) {
      pushHistory(sid);
      as.shapes.splice(hitIdx, 1);
      saveShapes(sid);
      redrawShapes(sid);
      showToast("Object deleted");
    }
    return;
  }

  // Drawing tools
  as.drawing = true;
  as.startX = pos.x;
  as.startY = pos.y;
  as.selectedIndex = -1;

  // Step number: instant placement on click
  if (currentTool === "stepnum") {
    if (!window._stepnumCounter[sid]) window._stepnumCounter[sid] = 0;
    window._stepnumCounter[sid]++;
    var prefix = window._stepnumPrefix || "Step-";
    pushHistory(sid);
    as.shapes.push({
      type: "stepnum",
      cx: pos.x, cy: pos.y,
      num: window._stepnumCounter[sid],
      prefix: prefix,
      color: "#ffffff",
      bgColor: currentColor,
      radius: 18
    });
    saveShapes(sid);
    redrawShapes(sid);
    as.drawing = false;
    return;
  }

  if (currentTool === "pen" || currentTool === "pixelEraser") {
    as.penPoints = [{ x: pos.x, y: pos.y }];
  }
}

function onMove(e, sid) {
  var as = getAS(sid);
  var pos = getPos(e, sid);

  // Dragging callout arrow tip
  if (as.draggingArrowTip && as.selectedIndex >= 0) {
    var shape = as.shapes[as.selectedIndex];
    if (shape && shape.type === "callout") {
      shape.arrowX = pos.x;
      shape.arrowY = pos.y;
      redrawShapes(sid);
    }
    return;
  }

  // Dragging selected object
  if (as.dragging && as.selectedIndex >= 0) {
    var dx = pos.x - as.startX;
    var dy = pos.y - as.startY;
    moveShape(as.shapes[as.selectedIndex], dx, dy);
    as.startX = pos.x;
    as.startY = pos.y;
    redrawShapes(sid);
    return;
  }

  if (!as.drawing) {
    // Change cursor on hover for select/objectEraser
    if (currentTool === "select" || currentTool === "objectEraser") {
      var hit = hitTest(as.shapes, pos.x, pos.y);
      if (as.canvas) {
        as.canvas.style.cursor = hit >= 0 ? (currentTool === "select" ? "move" : "pointer") : (currentTool === "select" ? "default" : "pointer");
      }
    }
    return;
  }

  e.preventDefault();

  if (currentTool === "pen" || currentTool === "pixelEraser") {
    as.penPoints.push({ x: pos.x, y: pos.y });
  }

  redrawShapes(sid);
  drawPreview(sid, pos.x, pos.y);
}

function onUp(e, sid) {
  var as = getAS(sid);
  var pos = getPos(e, sid);

  // Finish arrow tip drag
  if (as.draggingArrowTip) {
    as.draggingArrowTip = false;
    pushHistory(sid);
    saveShapes(sid);
    redrawShapes(sid);
    return;
  }

  // Finish drag
  if (as.dragging) {
    as.dragging = false;
    pushHistory(sid);
    saveShapes(sid);
    redrawShapes(sid);
    return;
  }

  if (!as.drawing) return;
  as.drawing = false;

  var shape = null;

  if (currentTool === "circle") {
    var rx = Math.abs(pos.x - as.startX) / 2;
    var ry = Math.abs(pos.y - as.startY) / 2;
    if (rx > 3 || ry > 3) {
      shape = { type: "circle", cx: (as.startX + pos.x) / 2, cy: (as.startY + pos.y) / 2, rx: rx, ry: ry, color: currentColor, size: currentSize };
    }
  } else if (currentTool === "rect") {
    var w = Math.abs(pos.x - as.startX), h = Math.abs(pos.y - as.startY);
    if (w > 3 || h > 3) {
      shape = { type: "rect", x: Math.min(as.startX, pos.x), y: Math.min(as.startY, pos.y), w: w, h: h, color: currentColor, size: currentSize };
    }
  } else if (currentTool === "arrow") {
    var d = Math.sqrt(Math.pow(pos.x - as.startX, 2) + Math.pow(pos.y - as.startY, 2));
    if (d > 5) {
      shape = { type: "arrow", x1: as.startX, y1: as.startY, x2: pos.x, y2: pos.y, color: currentColor, size: currentSize };
    }
  } else if (currentTool === "pen") {
    if (as.penPoints.length > 1) {
      shape = { type: "pen", points: as.penPoints.slice(), color: currentColor, size: currentSize };
    }
  } else if (currentTool === "pixelEraser") {
    if (as.penPoints.length > 1) {
      shape = { type: "eraser", points: as.penPoints.slice(), size: Math.max(currentSize * 4, 12) };
    }
  } else if (currentTool === "blur") {
    var w = Math.abs(pos.x - as.startX), h = Math.abs(pos.y - as.startY);
    if (w > 10 || h > 10) {
      shape = { type: "blur", x: Math.min(as.startX, pos.x), y: Math.min(as.startY, pos.y), w: w, h: h, intensity: window._blurIntensity || 10 };
    }
  } else if (currentTool === "callout") {
    var w = Math.abs(pos.x - as.startX), h = Math.abs(pos.y - as.startY);
    if (w > 20 || h > 20) {
      var bx = Math.min(as.startX, pos.x), by = Math.min(as.startY, pos.y);
      shape = {
        type: "callout",
        x: bx, y: by, w: Math.max(w, 80), h: Math.max(h, 40),
        arrowX: bx + w + 50, arrowY: by + h + 50,
        text: "Add text here",
        color: "#ffffff",
        bgColor: currentColor,
        radius: 12,
        fontSize: 14
      };
    }
  }

  if (shape) {
    pushHistory(sid);
    as.shapes.push(shape);
    saveShapes(sid);

    // Auto-open text editor for new callouts
    if (shape.type === "callout" && as.canvas) {
      as.selectedIndex = as.shapes.length - 1;
      redrawShapes(sid);
      setTimeout(function() { openCalloutEditor(sid, as.shapes.length - 1, as.canvas); }, 100);
    }
  }

  as.penPoints = [];
  redrawShapes(sid);
}

function pushHistory(sid) {
  var as = getAS(sid);
  as.history = as.history.slice(0, as.historyIndex + 1);
  as.history.push(JSON.parse(JSON.stringify(as.shapes)));
  as.historyIndex = as.history.length - 1;
}

function saveShapes(sid) {
  var as = getAS(sid);
  var step = state.steps.find(function(s) { return s.id === sid; });
  if (step) step.annotations = JSON.parse(JSON.stringify(as.shapes));
}

function undoAnnotation(sid) {
  var as = getAS(sid);
  if (!as || as.historyIndex <= 0) return;
  as.historyIndex--;
  as.shapes = JSON.parse(JSON.stringify(as.history[as.historyIndex]));
  as.selectedIndex = -1;
  saveShapes(sid);
  redrawShapes(sid);
  showToast("Undo");
}

// ============================================================
// DRAWING
// ============================================================

function redrawShapes(sid) {
  var as = getAS(sid);
  if (!as || !as.ctx) return;
  var ctx = as.ctx;
  ctx.clearRect(0, 0, as.canvas.width, as.canvas.height);

  as.shapes.forEach(function(shape, idx) {
    ctx.save();
    var isSelected = (idx === as.selectedIndex);

    if (shape.type === "eraser") {
      ctx.globalCompositeOperation = "destination-out";
      ctx.lineWidth = shape.size;
      ctx.lineCap = "round"; ctx.lineJoin = "round";
      if (shape.points.length > 1) {
        ctx.beginPath();
        ctx.moveTo(shape.points[0].x, shape.points[0].y);
        for (var i = 1; i < shape.points.length; i++) ctx.lineTo(shape.points[i].x, shape.points[i].y);
        ctx.stroke();
      }
      ctx.globalCompositeOperation = "source-over";
      ctx.restore();
      return;
    }

    // --- BLUR BOX ---
    if (shape.type === "blur") {
      drawBlurBox(ctx, as, shape, isSelected);
      ctx.restore();
      return;
    }

    // --- CALLOUT ---
    if (shape.type === "callout") {
      drawCallout(ctx, shape, isSelected);
      if (isSelected) drawCalloutHandles(ctx, shape);
      ctx.restore();
      return;
    }

    // --- STEP NUMBER ---
    if (shape.type === "stepnum") {
      drawStepNum(ctx, shape, isSelected);
      ctx.restore();
      return;
    }

    ctx.strokeStyle = shape.color || "#ef4444";
    ctx.lineWidth = shape.size || 3;
    ctx.lineCap = "round"; ctx.lineJoin = "round";

    // Selection highlight
    if (isSelected) {
      ctx.shadowColor = "#3b82f6";
      ctx.shadowBlur = 8;
      ctx.setLineDash([6, 4]);
    }

    if (shape.type === "circle") {
      ctx.beginPath();
      ctx.ellipse(shape.cx, shape.cy, Math.max(shape.rx, 1), Math.max(shape.ry, 1), 0, 0, Math.PI * 2);
      ctx.stroke();
    } else if (shape.type === "rect") {
      ctx.beginPath();
      ctx.rect(shape.x, shape.y, shape.w, shape.h);
      ctx.stroke();
    } else if (shape.type === "arrow") {
      drawArrow(ctx, shape.x1, shape.y1, shape.x2, shape.y2, shape.color, shape.size);
    } else if (shape.type === "pen" && shape.points.length > 1) {
      ctx.beginPath();
      ctx.moveTo(shape.points[0].x, shape.points[0].y);
      for (var i = 1; i < shape.points.length; i++) ctx.lineTo(shape.points[i].x, shape.points[i].y);
      ctx.stroke();
    }

    // Draw selection handles
    if (isSelected) {
      ctx.setLineDash([]);
      ctx.shadowBlur = 0;
      var bb = getShapeBBox(shape);
      if (bb) {
        var handles = [
          { x: bb.x, y: bb.y }, { x: bb.x + bb.w, y: bb.y },
          { x: bb.x, y: bb.y + bb.h }, { x: bb.x + bb.w, y: bb.y + bb.h }
        ];
        handles.forEach(function(h) {
          ctx.fillStyle = "#3b82f6";
          ctx.strokeStyle = "#fff";
          ctx.lineWidth = 2;
          ctx.beginPath();
          ctx.arc(h.x, h.y, 5, 0, Math.PI * 2);
          ctx.fill();
          ctx.stroke();
        });
      }
    }

    ctx.restore();
  });
}

// --- Blur Box Drawing ---

function drawBlurBox(ctx, as, shape, isSelected) {
  // Get image data from the underlying screenshot
  var step = state.steps.find(function(s) { return s.id && annoState[s.id] === as; });
  var imgEl = as.canvas.parentElement ? as.canvas.parentElement.querySelector("img") : null;

  var x = Math.round(shape.x), y = Math.round(shape.y);
  var w = Math.round(shape.w), h = Math.round(shape.h);
  var intensity = shape.intensity || 10;

  // Draw semi-transparent overlay to indicate blur
  ctx.fillStyle = "rgba(128, 128, 128, 0.3)";
  roundRect(ctx, x, y, w, h, 4);
  ctx.fill();

  // Simulate blur with multiple semi-transparent layers
  ctx.fillStyle = "rgba(200, 200, 200, 0.15)";
  for (var i = 0; i < Math.min(intensity, 15); i++) {
    var offset = i * 0.8;
    roundRect(ctx, x + offset, y + offset, w - offset * 2, h - offset * 2, 4);
    ctx.fill();
  }

  // Blur pattern lines
  ctx.strokeStyle = "rgba(150, 150, 150, 0.4)";
  ctx.lineWidth = 1;
  for (var ly = y + 3; ly < y + h - 3; ly += 4) {
    ctx.beginPath();
    ctx.moveTo(x + 3, ly);
    ctx.lineTo(x + w - 3, ly);
    ctx.stroke();
  }

  // Border
  ctx.strokeStyle = isSelected ? "#3b82f6" : "rgba(100, 100, 100, 0.5)";
  ctx.lineWidth = isSelected ? 2 : 1;
  ctx.setLineDash(isSelected ? [6, 4] : [4, 3]);
  roundRect(ctx, x, y, w, h, 4);
  ctx.stroke();
  ctx.setLineDash([]);

  // Selection handles
  if (isSelected) {
    var corners = [
      { x: x, y: y }, { x: x + w, y: y },
      { x: x, y: y + h }, { x: x + w, y: y + h }
    ];
    corners.forEach(function(c) {
      ctx.fillStyle = "#3b82f6"; ctx.strokeStyle = "#fff"; ctx.lineWidth = 2;
      ctx.beginPath(); ctx.arc(c.x, c.y, 5, 0, Math.PI * 2); ctx.fill(); ctx.stroke();
    });
  }
}

// --- Callout Drawing ---

function drawCallout(ctx, shape, isSelected) {
  var x = shape.x, y = shape.y, w = shape.w, h = shape.h;
  var r = shape.radius || 12;
  var bgColor = shape.bgColor || "#ef4444";
  var textColor = shape.color || "#ffffff";

  // Draw arrow line from box edge to arrow point
  var boxCenterX = x + w / 2, boxCenterY = y + h / 2;
  var arrowX = shape.arrowX, arrowY = shape.arrowY;

  // Find edge intersection point
  var edgePt = getBoxEdgePoint(x, y, w, h, arrowX, arrowY);

  ctx.save();
  ctx.strokeStyle = bgColor;
  ctx.lineWidth = 3;
  ctx.lineCap = "round";
  ctx.beginPath();
  ctx.moveTo(edgePt.x, edgePt.y);
  ctx.lineTo(arrowX, arrowY);
  ctx.stroke();

  // Arrow head
  var headLen = 14;
  var angle = Math.atan2(arrowY - edgePt.y, arrowX - edgePt.x);
  ctx.fillStyle = bgColor;
  ctx.beginPath();
  ctx.moveTo(arrowX, arrowY);
  ctx.lineTo(arrowX - headLen * Math.cos(angle - Math.PI / 6), arrowY - headLen * Math.sin(angle - Math.PI / 6));
  ctx.lineTo(arrowX - headLen * Math.cos(angle + Math.PI / 6), arrowY - headLen * Math.sin(angle + Math.PI / 6));
  ctx.closePath();
  ctx.fill();
  ctx.restore();

  // Draw rounded rectangle box
  ctx.save();
  if (isSelected) {
    ctx.shadowColor = "#3b82f6";
    ctx.shadowBlur = 10;
  }
  ctx.fillStyle = bgColor;
  roundRect(ctx, x, y, w, h, r);
  ctx.fill();
  ctx.restore();

  // Draw text
  ctx.save();
  ctx.fillStyle = textColor;
  ctx.font = "bold " + (shape.fontSize || 14) + "px -apple-system, BlinkMacSystemFont, sans-serif";
  ctx.textAlign = "center";
  ctx.textBaseline = "middle";

  // Word wrap
  var lines = wrapText(ctx, shape.text || "", w - 16);
  var lineHeight = (shape.fontSize || 14) * 1.3;
  var totalHeight = lines.length * lineHeight;
  var startY = y + h / 2 - totalHeight / 2 + lineHeight / 2;

  lines.forEach(function(line, i) {
    ctx.fillText(line, x + w / 2, startY + i * lineHeight);
  });
  ctx.restore();
}

function drawCalloutHandles(ctx, shape) {
  // Box corner handles
  var corners = [
    { x: shape.x, y: shape.y },
    { x: shape.x + shape.w, y: shape.y },
    { x: shape.x, y: shape.y + shape.h },
    { x: shape.x + shape.w, y: shape.y + shape.h }
  ];
  corners.forEach(function(c) {
    ctx.fillStyle = "#3b82f6"; ctx.strokeStyle = "#fff"; ctx.lineWidth = 2;
    ctx.beginPath(); ctx.arc(c.x, c.y, 5, 0, Math.PI * 2); ctx.fill(); ctx.stroke();
  });

  // Arrow tip handle (larger, different color)
  ctx.fillStyle = "#f59e0b"; ctx.strokeStyle = "#fff"; ctx.lineWidth = 2;
  ctx.beginPath(); ctx.arc(shape.arrowX, shape.arrowY, 7, 0, Math.PI * 2); ctx.fill(); ctx.stroke();
}

function getBoxEdgePoint(bx, by, bw, bh, px, py) {
  var cx = bx + bw / 2, cy = by + bh / 2;
  var dx = px - cx, dy = py - cy;
  if (dx === 0 && dy === 0) return { x: cx, y: by };

  var absDx = Math.abs(dx), absDy = Math.abs(dy);
  var scaleX = (bw / 2) / (absDx || 1);
  var scaleY = (bh / 2) / (absDy || 1);
  var scale = Math.min(scaleX, scaleY);

  return { x: cx + dx * scale, y: cy + dy * scale };
}

function wrapText(ctx, text, maxWidth) {
  var words = text.split(" ");
  var lines = [];
  var currentLine = words[0] || "";

  for (var i = 1; i < words.length; i++) {
    var testLine = currentLine + " " + words[i];
    if (ctx.measureText(testLine).width <= maxWidth) {
      currentLine = testLine;
    } else {
      lines.push(currentLine);
      currentLine = words[i];
    }
  }
  lines.push(currentLine);
  return lines;
}

// --- Step Number Drawing ---

function drawStepNum(ctx, shape, isSelected) {
  var cx = shape.cx, cy = shape.cy;
  var r = shape.radius || 18;
  var bgColor = shape.bgColor || "#ef4444";
  var textColor = shape.color || "#ffffff";
  var label = (shape.prefix || "") + shape.num;

  // Measure text to auto-size the badge
  ctx.save();
  ctx.font = "bold 13px -apple-system, BlinkMacSystemFont, sans-serif";
  var textW = ctx.measureText(label).width;
  var badgeW = Math.max(textW + 16, r * 2);
  var badgeH = r * 2;

  // Draw pill shape
  if (isSelected) { ctx.shadowColor = "#3b82f6"; ctx.shadowBlur = 10; }
  ctx.fillStyle = bgColor;
  roundRect(ctx, cx - badgeW / 2, cy - badgeH / 2, badgeW, badgeH, r);
  ctx.fill();

  // Border
  ctx.strokeStyle = "rgba(255,255,255,0.5)";
  ctx.lineWidth = 2;
  roundRect(ctx, cx - badgeW / 2, cy - badgeH / 2, badgeW, badgeH, r);
  ctx.stroke();

  // Text
  ctx.fillStyle = textColor;
  ctx.font = "bold 13px -apple-system, BlinkMacSystemFont, sans-serif";
  ctx.textAlign = "center";
  ctx.textBaseline = "middle";
  ctx.fillText(label, cx, cy);
  ctx.restore();

  // Selection handles
  if (isSelected) {
    ctx.fillStyle = "#3b82f6"; ctx.strokeStyle = "#fff"; ctx.lineWidth = 2;
    ctx.beginPath(); ctx.arc(cx - badgeW / 2, cy, 5, 0, Math.PI * 2); ctx.fill(); ctx.stroke();
    ctx.beginPath(); ctx.arc(cx + badgeW / 2, cy, 5, 0, Math.PI * 2); ctx.fill(); ctx.stroke();
  }
}

// --- Inline Callout Text Editor ---

function openCalloutEditor(sid, shapeIdx, canvas) {
  // Remove any existing editor
  var existing = document.querySelector(".callout-text-editor");
  if (existing) existing.remove();

  var as = getAS(sid);
  var shape = as.shapes[shapeIdx];
  if (!shape) return;

  var canvasRect = canvas.getBoundingClientRect();

  // Create editor overlay
  var editor = document.createElement("div");
  editor.className = "callout-text-editor";
  editor.style.cssText = "position:fixed;z-index:99999;left:" + (canvasRect.left + shape.x) + "px;top:" + (canvasRect.top + shape.y) + "px;" +
    "width:" + shape.w + "px;min-height:" + shape.h + "px;display:flex;flex-direction:column;gap:4px;padding:4px;" +
    "background:" + (shape.bgColor || "#ef4444") + ";border-radius:" + (shape.radius || 12) + "px;" +
    "box-shadow:0 4px 20px rgba(0,0,0,0.4);border:2px solid #3b82f6;";

  var textarea = document.createElement("textarea");
  textarea.value = shape.text || "";
  textarea.style.cssText = "width:100%;min-height:" + (shape.h - 40) + "px;background:transparent;border:none;outline:none;resize:none;" +
    "color:" + (shape.color || "#fff") + ";font-family:-apple-system,BlinkMacSystemFont,sans-serif;" +
    "font-size:" + (shape.fontSize || 14) + "px;font-weight:bold;text-align:center;padding:6px;";
  textarea.placeholder = "Type your text here...";

  var btnRow = document.createElement("div");
  btnRow.style.cssText = "display:flex;gap:4px;justify-content:center;";

  var saveBtn = document.createElement("button");
  saveBtn.textContent = "✓ Save";
  saveBtn.style.cssText = "padding:3px 12px;background:rgba(255,255,255,0.25);color:#fff;border:1px solid rgba(255,255,255,0.4);" +
    "border-radius:6px;cursor:pointer;font-size:11px;font-weight:600;font-family:inherit;";

  var cancelBtn = document.createElement("button");
  cancelBtn.textContent = "✕";
  cancelBtn.style.cssText = "padding:3px 8px;background:rgba(0,0,0,0.2);color:#fff;border:1px solid rgba(255,255,255,0.2);" +
    "border-radius:6px;cursor:pointer;font-size:11px;font-family:inherit;";

  function saveAndClose() {
    pushHistory(sid);
    shape.text = textarea.value || "Add text here";
    saveShapes(sid);
    redrawShapes(sid);
    editor.remove();
  }

  saveBtn.addEventListener("click", saveAndClose);
  cancelBtn.addEventListener("click", function() { editor.remove(); });
  textarea.addEventListener("keydown", function(e) {
    e.stopPropagation(); // Prevent Ctrl+S from triggering project save
    if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); saveAndClose(); }
    if (e.key === "Escape") editor.remove();
  });

  btnRow.appendChild(saveBtn);
  btnRow.appendChild(cancelBtn);
  editor.appendChild(textarea);
  editor.appendChild(btnRow);
  document.body.appendChild(editor);
  textarea.focus();
  textarea.select();
}

function roundRect(ctx, x, y, w, h, r) {
  r = Math.min(r, w / 2, h / 2);
  ctx.beginPath();
  ctx.moveTo(x + r, y);
  ctx.lineTo(x + w - r, y);
  ctx.arcTo(x + w, y, x + w, y + r, r);
  ctx.lineTo(x + w, y + h - r);
  ctx.arcTo(x + w, y + h, x + w - r, y + h, r);
  ctx.lineTo(x + r, y + h);
  ctx.arcTo(x, y + h, x, y + h - r, r);
  ctx.lineTo(x, y + r);
  ctx.arcTo(x, y, x + r, y, r);
  ctx.closePath();
}

function getShapeBBox(s) {
  if (s.type === "circle") return { x: s.cx - s.rx, y: s.cy - s.ry, w: s.rx * 2, h: s.ry * 2 };
  if (s.type === "rect") return { x: s.x, y: s.y, w: s.w, h: s.h };
  if (s.type === "arrow") {
    var minX = Math.min(s.x1, s.x2), minY = Math.min(s.y1, s.y2);
    return { x: minX, y: minY, w: Math.abs(s.x2 - s.x1), h: Math.abs(s.y2 - s.y1) };
  }
  if (s.type === "blur") return { x: s.x, y: s.y, w: s.w, h: s.h };
  if (s.type === "callout") return { x: s.x, y: s.y, w: s.w, h: s.h };
  if (s.type === "stepnum") { var r = s.radius || 18; return { x: s.cx - r, y: s.cy - r, w: r * 2, h: r * 2 }; }
  if (s.type === "pen" && s.points.length > 0) {
    var minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    s.points.forEach(function(p) { minX = Math.min(minX, p.x); minY = Math.min(minY, p.y); maxX = Math.max(maxX, p.x); maxY = Math.max(maxY, p.y); });
    return { x: minX, y: minY, w: maxX - minX, h: maxY - minY };
  }
  return null;
}

function drawPreview(sid, mx, my) {
  var as = getAS(sid);
  var ctx = as.ctx;
  ctx.save();
  ctx.strokeStyle = currentColor;
  ctx.lineWidth = currentSize;
  ctx.lineCap = "round"; ctx.lineJoin = "round";
  ctx.setLineDash([4, 4]);

  if (currentTool === "circle") {
    var rx = Math.abs(mx - as.startX) / 2, ry = Math.abs(my - as.startY) / 2;
    ctx.beginPath();
    ctx.ellipse((as.startX + mx) / 2, (as.startY + my) / 2, rx, ry, 0, 0, Math.PI * 2);
    ctx.stroke();
  } else if (currentTool === "rect") {
    ctx.beginPath();
    ctx.rect(Math.min(as.startX, mx), Math.min(as.startY, my), Math.abs(mx - as.startX), Math.abs(my - as.startY));
    ctx.stroke();
  } else if (currentTool === "arrow") {
    ctx.setLineDash([]);
    drawArrow(ctx, as.startX, as.startY, mx, my, currentColor, currentSize);
  } else if (currentTool === "pen" && as.penPoints.length > 1) {
    ctx.setLineDash([]);
    ctx.beginPath();
    ctx.moveTo(as.penPoints[0].x, as.penPoints[0].y);
    for (var i = 1; i < as.penPoints.length; i++) ctx.lineTo(as.penPoints[i].x, as.penPoints[i].y);
    ctx.stroke();
  } else if (currentTool === "pixelEraser" && as.penPoints.length > 1) {
    ctx.globalCompositeOperation = "destination-out";
    ctx.lineWidth = Math.max(currentSize * 4, 12);
    ctx.setLineDash([]);
    ctx.beginPath();
    ctx.moveTo(as.penPoints[0].x, as.penPoints[0].y);
    for (var i = 1; i < as.penPoints.length; i++) ctx.lineTo(as.penPoints[i].x, as.penPoints[i].y);
    ctx.stroke();
    ctx.globalCompositeOperation = "source-over";
  } else if (currentTool === "blur") {
    ctx.fillStyle = "rgba(128, 128, 128, 0.3)";
    ctx.setLineDash([]);
    ctx.fillRect(Math.min(as.startX, mx), Math.min(as.startY, my), Math.abs(mx - as.startX), Math.abs(my - as.startY));
    ctx.strokeStyle = "rgba(100, 100, 100, 0.5)";
    ctx.lineWidth = 1;
    ctx.strokeRect(Math.min(as.startX, mx), Math.min(as.startY, my), Math.abs(mx - as.startX), Math.abs(my - as.startY));
  } else if (currentTool === "callout") {
    var bx = Math.min(as.startX, mx), by = Math.min(as.startY, my);
    var bw = Math.abs(mx - as.startX), bh = Math.abs(my - as.startY);
    ctx.setLineDash([]);
    ctx.fillStyle = currentColor;
    ctx.globalAlpha = 0.7;
    roundRect(ctx, bx, by, bw, bh, 12);
    ctx.fill();
    ctx.globalAlpha = 1;
  }
  ctx.restore();
}

function drawArrow(ctx, x1, y1, x2, y2, color, size) {
  var headLen = Math.max(size * 4, 12);
  var angle = Math.atan2(y2 - y1, x2 - x1);
  ctx.save();
  ctx.strokeStyle = color; ctx.fillStyle = color;
  ctx.lineWidth = size; ctx.lineCap = "round";
  ctx.setLineDash([]);
  ctx.beginPath(); ctx.moveTo(x1, y1); ctx.lineTo(x2, y2); ctx.stroke();
  ctx.beginPath(); ctx.moveTo(x2, y2);
  ctx.lineTo(x2 - headLen * Math.cos(angle - Math.PI/6), y2 - headLen * Math.sin(angle - Math.PI/6));
  ctx.lineTo(x2 - headLen * Math.cos(angle + Math.PI/6), y2 - headLen * Math.sin(angle + Math.PI/6));
  ctx.closePath(); ctx.fill();
  ctx.restore();
}

// ============================================================
// MERGE FOR EXPORT
// ============================================================

function getMergedImage(step) {
  return new Promise(function(resolve) {
    if (!step.screenshot) { resolve(null); return; }
    var shapes = step.annotations || [];
    if (shapes.length === 0) { resolve(step.screenshot); return; }

    var img = new Image();
    img.onload = function() {
      var as = annoState[step.id];
      var displayW = as ? as.imgW : img.naturalWidth;
      var displayH = as ? as.imgH : img.naturalHeight;
      var scaleX = img.naturalWidth / (displayW || 1);
      var scaleY = img.naturalHeight / (displayH || 1);

      var tc = document.createElement("canvas");
      tc.width = img.naturalWidth; tc.height = img.naturalHeight;
      var tctx = tc.getContext("2d");
      tctx.drawImage(img, 0, 0);

      shapes.forEach(function(s) {
        if (s.type === "eraser") return;
        tctx.save();
        tctx.strokeStyle = s.color || "#ef4444";
        tctx.lineWidth = (s.size || 3) * scaleX;
        tctx.lineCap = "round"; tctx.lineJoin = "round";
        if (s.type === "circle") { tctx.beginPath(); tctx.ellipse(s.cx*scaleX, s.cy*scaleY, s.rx*scaleX, s.ry*scaleY, 0, 0, Math.PI*2); tctx.stroke(); }
        else if (s.type === "rect") { tctx.beginPath(); tctx.rect(s.x*scaleX, s.y*scaleY, s.w*scaleX, s.h*scaleY); tctx.stroke(); }
        else if (s.type === "arrow") { drawArrow(tctx, s.x1*scaleX, s.y1*scaleY, s.x2*scaleX, s.y2*scaleY, s.color, (s.size||3)*scaleX); }
        else if (s.type === "pen" && s.points.length > 1) {
          tctx.beginPath(); tctx.moveTo(s.points[0].x*scaleX, s.points[0].y*scaleY);
          for (var i = 1; i < s.points.length; i++) tctx.lineTo(s.points[i].x*scaleX, s.points[i].y*scaleY);
          tctx.stroke();
        }
        else if (s.type === "blur") {
          // Apply real blur using CanvasRenderingContext2D.filter
          var bx = s.x*scaleX, by = s.y*scaleY, bw = s.w*scaleX, bh = s.h*scaleY;
          var tempCanvas = document.createElement("canvas");
          tempCanvas.width = Math.max(1, Math.round(bw));
          tempCanvas.height = Math.max(1, Math.round(bh));
          var tempCtx = tempCanvas.getContext("2d");
          tempCtx.drawImage(tc, bx, by, bw, bh, 0, 0, bw, bh);
          tctx.save();
          tctx.filter = "blur(" + (s.intensity || 10) + "px)";
          tctx.drawImage(tempCanvas, bx, by, bw, bh);
          tctx.restore();
        }
        else if (s.type === "callout") {
          // Arrow line
          var edgePt = getBoxEdgePoint(s.x*scaleX, s.y*scaleY, s.w*scaleX, s.h*scaleY, s.arrowX*scaleX, s.arrowY*scaleY);
          tctx.strokeStyle = s.bgColor || "#ef4444";
          tctx.lineWidth = 3 * scaleX;
          tctx.beginPath(); tctx.moveTo(edgePt.x, edgePt.y); tctx.lineTo(s.arrowX*scaleX, s.arrowY*scaleY); tctx.stroke();
          // Arrow head
          var headLen = 14 * scaleX;
          var angle = Math.atan2(s.arrowY*scaleY - edgePt.y, s.arrowX*scaleX - edgePt.x);
          tctx.fillStyle = s.bgColor || "#ef4444";
          tctx.beginPath(); tctx.moveTo(s.arrowX*scaleX, s.arrowY*scaleY);
          tctx.lineTo(s.arrowX*scaleX - headLen * Math.cos(angle - Math.PI/6), s.arrowY*scaleY - headLen * Math.sin(angle - Math.PI/6));
          tctx.lineTo(s.arrowX*scaleX - headLen * Math.cos(angle + Math.PI/6), s.arrowY*scaleY - headLen * Math.sin(angle + Math.PI/6));
          tctx.closePath(); tctx.fill();
          // Box
          tctx.fillStyle = s.bgColor || "#ef4444";
          roundRect(tctx, s.x*scaleX, s.y*scaleY, s.w*scaleX, s.h*scaleY, (s.radius||12)*scaleX);
          tctx.fill();
          // Text
          tctx.fillStyle = s.color || "#fff";
          tctx.font = "bold " + Math.round((s.fontSize || 14) * scaleX) + "px -apple-system, BlinkMacSystemFont, sans-serif";
          tctx.textAlign = "center"; tctx.textBaseline = "middle";
          var lines = wrapText(tctx, s.text || "", s.w * scaleX - 16);
          var lh = (s.fontSize || 14) * scaleX * 1.3;
          var sy = s.y * scaleY + s.h * scaleY / 2 - lines.length * lh / 2 + lh / 2;
          lines.forEach(function(line, li) { tctx.fillText(line, s.x * scaleX + s.w * scaleX / 2, sy + li * lh); });
        }
        else if (s.type === "stepnum") {
          var cx = s.cx*scaleX, cy = s.cy*scaleY, r = (s.radius||18)*scaleX;
          var label = (s.prefix || "") + s.num;
          tctx.font = "bold " + Math.round(13 * scaleX) + "px -apple-system, BlinkMacSystemFont, sans-serif";
          var tw = tctx.measureText(label).width;
          var bw = Math.max(tw + 16 * scaleX, r * 2);
          tctx.fillStyle = s.bgColor || "#ef4444";
          roundRect(tctx, cx - bw/2, cy - r, bw, r*2, r);
          tctx.fill();
          tctx.strokeStyle = "rgba(255,255,255,0.5)"; tctx.lineWidth = 2 * scaleX;
          roundRect(tctx, cx - bw/2, cy - r, bw, r*2, r);
          tctx.stroke();
          tctx.fillStyle = s.color || "#fff"; tctx.textAlign = "center"; tctx.textBaseline = "middle";
          tctx.fillText(label, cx, cy);
        }
        tctx.restore();
      });
      resolve(tc.toDataURL("image/png"));
    };
    img.src = step.screenshot;
  });
}

// ============================================================
// STEP OPERATIONS
// ============================================================

function selectStep(id) { state.activeStepId = id; render(); var el = document.getElementById("editor-" + id); if (el) el.scrollIntoView({ behavior: "smooth", block: "center" }); }
function updateStepField(id, field, value) { var s = state.steps.find(function(s) { return s.id === id; }); if (s) s[field] = value; }
function deleteStep(id) { if (!confirm("Delete?")) return; state.steps = state.steps.filter(function(s) { return s.id !== id; }); delete annoState[id]; if (state.activeStepId === id) state.activeStepId = state.steps.length > 0 ? state.steps[0].id : null; render(); }
function moveStep(id, dir) { var idx = state.steps.findIndex(function(s) { return s.id === id; }); var ni = idx + dir; if (ni < 0 || ni >= state.steps.length) return; var t = state.steps[idx]; state.steps[idx] = state.steps[ni]; state.steps[ni] = t; render(); }
function addManualStep() { var ns = { id: "step_m_" + Date.now(), title: "New Step", description: "", screenshot: null, url: "", element: {}, annotations: [], timestamp: new Date().toISOString() }; state.steps.push(ns); state.activeStepId = ns.id; showEditor(); render(); }
function uploadScreenshot(sid) { pendingScreenshotStepId = sid; document.getElementById("screenshotFileInput").click(); }
function updateBrand() { state.brand.name = document.getElementById("brandName").value; state.brand.primaryColor = document.getElementById("brandColor").value; state.brand.accentColor = document.getElementById("accentColor").value; document.getElementById("brandColorHex").value = state.brand.primaryColor; document.getElementById("accentColorHex").value = state.brand.accentColor; render(); }
function generateDescription(sid) {
  var step = state.steps.find(function(s) { return s.id === sid; });
  if (!step) return;
  var el = step.element || {};
  var tag = (el.tag || "").toUpperCase();
  var text = (el.text || "").trim().substring(0, 80);
  var placeholder = el.placeholder || "";
  var ariaLabel = el.ariaLabel || "";
  var label = text || ariaLabel || placeholder || "";
  var site = hostname(step.url);
  var pageTitle = (step.pageTitle || "").split(/[\|\-\:—]/)[0].trim();

  var desc = "";

  // Smart descriptions based on what was clicked
  if (tag === "BUTTON" || (tag === "INPUT" && el.type === "submit")) {
    desc = 'Click the "' + label + '" button';
    if (site) desc += " on " + site;
    desc += ".";
  } else if (tag === "A") {
    if (el.href && el.href.length > 5) {
      desc = 'Click the "' + label + '" link';
      if (site) desc += " on " + site;
      desc += ".";
    } else {
      desc = 'Click on "' + label + '"';
      if (site) desc += " on " + site;
      desc += ".";
    }
  } else if (tag === "INPUT" || tag === "TEXTAREA" || tag === "SELECT") {
    var fieldName = placeholder || ariaLabel || el.id || "the field";
    if (tag === "SELECT") {
      desc = 'Open the "' + fieldName + '" dropdown and select your option.';
    } else {
      desc = 'Click on the "' + fieldName + '" field and enter the required information.';
    }
  } else if (tag === "IMG") {
    desc = "Click on the image";
    if (site) desc += " on " + site;
    desc += ".";
  } else if (tag === "NAV" || tag === "LI" || tag === "SPAN" || tag === "DIV" || tag === "SVG" || tag === "PATH") {
    if (label && label.length > 1 && label.length < 60) {
      desc = 'Click on "' + label + '"';
      if (site) desc += " on " + site;
      desc += ".";
    } else if (pageTitle) {
      desc = "Navigate to the " + pageTitle + " page";
      if (site) desc += " on " + site;
      desc += " and click on the highlighted element.";
    } else if (site) {
      desc = "Click on the highlighted area on " + site + ".";
    } else {
      desc = "Click on the highlighted element on the page.";
    }
  } else {
    if (label && label.length > 1) {
      desc = 'Click on "' + label + '"';
    } else if (pageTitle) {
      desc = "On the " + pageTitle + " page, click the highlighted area";
    } else {
      desc = "Click on the highlighted element";
    }
    if (site) desc += " on " + site;
    desc += ".";
  }

  step.description = desc;

  // Update the textarea directly without full re-render
  var ta = document.querySelector('.desc-inp[data-sid="' + sid + '"]');
  if (ta) { ta.value = desc; }
  showToast("Description generated!");
}
function generateAllDescriptions() { state.steps.forEach(function(s) { if (!s.description) generateDescription(s.id); }); showToast("All descriptions generated!"); }

// ============================================================
// VOICE DICTATION IN EDITOR
// ============================================================

var editorMediaRecorder = null;
var editorAudioChunks = [];
var editorMicStream = null;
var activeDictationSid = null;

function toggleDictation(sid, btn) {
  if (activeDictationSid === sid && editorMediaRecorder && editorMediaRecorder.state === "recording") {
    // Stop dictation
    stopDictation(sid, btn);
  } else {
    // Start dictation
    startDictation(sid, btn);
  }
}

function startDictation(sid, btn) {
  // Stop any existing dictation
  if (editorMediaRecorder && editorMediaRecorder.state === "recording") {
    editorMediaRecorder.stop();
    if (editorMicStream) editorMicStream.getTracks().forEach(function(t) { t.stop(); });
  }

  activeDictationSid = sid;
  btn.textContent = "\ud83d\udd34 Recording...";
  btn.style.background = "rgba(239,68,68,0.15)";
  btn.style.color = "#f87171";
  btn.style.borderColor = "rgba(239,68,68,0.3)";

  navigator.mediaDevices.getUserMedia({ audio: true }).then(function(stream) {
    editorMicStream = stream;
    editorMediaRecorder = new MediaRecorder(stream, { mimeType: "audio/webm" });
    editorAudioChunks = [];

    editorMediaRecorder.ondataavailable = function(e) {
      if (e.data.size > 0) editorAudioChunks.push(e.data);
    };

    editorMediaRecorder.start();
    showToast("Listening... click Dictate again to stop");
  }).catch(function(err) {
    showToast("Mic access denied: " + err.message);
    resetDictateBtn(btn);
    activeDictationSid = null;
  });
}

function stopDictation(sid, btn) {
  if (!editorMediaRecorder || editorMediaRecorder.state === "inactive") {
    resetDictateBtn(btn);
    activeDictationSid = null;
    return;
  }

  btn.textContent = "\u23f3 Transcribing...";

  editorMediaRecorder.onstop = function() {
    if (editorAudioChunks.length === 0) {
      showToast("No audio captured");
      resetDictateBtn(btn);
      activeDictationSid = null;
      return;
    }

    var blob = new Blob(editorAudioChunks, { type: "audio/webm" });
    editorAudioChunks = [];

    if (blob.size < 1000) {
      showToast("Audio too short — speak longer");
      resetDictateBtn(btn);
      activeDictationSid = null;
      return;
    }

    var reader = new FileReader();
    reader.onloadend = function() {
      var audioBase64 = reader.result;

      // Send to background for Whisper transcription
      chrome.runtime.sendMessage({
        action: "WHISPER_TRANSCRIBE",
        audioBase64: audioBase64,
        stepId: null // Don't auto-update step in background, we'll do it here
      }, function(res) {
        if (res && res.success && res.text) {
          // Update textarea
          var ta = document.querySelector('.desc-inp[data-sid="' + sid + '"]');
          if (ta) {
            // Append to existing text
            var existing = ta.value.trim();
            ta.value = existing ? existing + " " + res.text : res.text;
            updateStepField(sid, "description", ta.value);
          }
          showToast("Transcription added!");
        } else {
          showToast(res ? res.error : "Transcription failed");
        }
        resetDictateBtn(btn);
        activeDictationSid = null;
      });
    };
    reader.readAsDataURL(blob);

    // Release mic
    if (editorMicStream) {
      editorMicStream.getTracks().forEach(function(t) { t.stop(); });
      editorMicStream = null;
    }
  };

  editorMediaRecorder.stop();
}

function resetDictateBtn(btn) {
  btn.textContent = "\ud83c\udfa4 Dictate";
  btn.style.background = "";
  btn.style.color = "";
  btn.style.borderColor = "";
}

// --- Title Dictation ---
var titleDictationSid = null;
var titleMicStream = null;
var titleMediaRecorder = null;
var titleAudioChunks = [];

function toggleTitleDictation(sid, btn) {
  if (titleDictationSid === sid) {
    stopTitleDictation(sid, btn);
  } else {
    startTitleDictation(sid, btn);
  }
}

function startTitleDictation(sid, btn) {
  // Stop any existing
  if (titleDictationSid) {
    var oldBtn = document.querySelector('.mic-title-dictate[data-sid="' + titleDictationSid + '"]');
    if (oldBtn) resetTitleMicBtn(oldBtn);
    if (titleMicStream) titleMicStream.getTracks().forEach(function(t) { t.stop(); });
  }

  titleDictationSid = sid;
  btn.textContent = "\ud83d\udd34";
  btn.style.background = "rgba(239,68,68,0.15)";
  btn.style.color = "#f87171";
  btn.title = "Recording... click to stop";

  navigator.mediaDevices.getUserMedia({ audio: true }).then(function(stream) {
    titleMicStream = stream;
    titleMediaRecorder = new MediaRecorder(stream, { mimeType: "audio/webm" });
    titleAudioChunks = [];

    titleMediaRecorder.ondataavailable = function(e) {
      if (e.data.size > 0) titleAudioChunks.push(e.data);
    };

    titleMediaRecorder.start();
    showToast("Listening for title... click mic again to stop");
  }).catch(function(err) {
    showToast("Mic access denied: " + err.message);
    resetTitleMicBtn(btn);
    titleDictationSid = null;
  });
}

function stopTitleDictation(sid, btn) {
  if (!titleMediaRecorder || titleMediaRecorder.state === "inactive") {
    resetTitleMicBtn(btn);
    titleDictationSid = null;
    return;
  }

  btn.textContent = "\u23f3";
  btn.title = "Transcribing...";

  titleMediaRecorder.onstop = function() {
    if (titleAudioChunks.length === 0) {
      showToast("No audio captured");
      resetTitleMicBtn(btn);
      titleDictationSid = null;
      return;
    }

    var blob = new Blob(titleAudioChunks, { type: "audio/webm" });
    titleAudioChunks = [];

    if (blob.size < 1000) {
      showToast("Audio too short");
      resetTitleMicBtn(btn);
      titleDictationSid = null;
      return;
    }

    var reader = new FileReader();
    reader.onloadend = function() {
      chrome.runtime.sendMessage({
        action: "WHISPER_TRANSCRIBE",
        audioBase64: reader.result,
        stepId: null
      }, function(res) {
        if (res && res.success && res.text) {
          var inp = document.querySelector('.title-inp[data-sid="' + sid + '"]');
          if (inp) {
            inp.value = res.text;
            updateStepField(sid, "title", res.text);
            renderSidebar();
          }
          showToast("Title updated!");
        } else {
          showToast(res ? res.error : "Transcription failed");
        }
        resetTitleMicBtn(btn);
        titleDictationSid = null;
      });
    };
    reader.readAsDataURL(blob);

    if (titleMicStream) {
      titleMicStream.getTracks().forEach(function(t) { t.stop(); });
      titleMicStream = null;
    }
  };

  titleMediaRecorder.stop();
}

function resetTitleMicBtn(btn) {
  if (!btn) return;
  btn.textContent = "\ud83c\udfa4";
  btn.style.background = "";
  btn.style.color = "";
  btn.title = "Dictate title";
}

// ============================================================
// TEXT-TO-SPEECH PLAYBACK
// ============================================================

function ttsPlayStep(sid, btn) {
  // If already playing this step, stop it
  if (ttsPlayingSid === sid && ttsAudio && !ttsAudio.paused) {
    ttsStop();
    return;
  }

  // Stop current audio without killing PlayAll mode
  var wasPlayAll = ttsPlayAllMode;
  if (ttsAudio) {
    ttsAudio.pause();
    ttsAudio.currentTime = 0;
    ttsAudio.onended = null;
    ttsAudio = null;
  }
  if (ttsPlayingSid) {
    var oldBtn = document.querySelector('.tts-play[data-sid="' + ttsPlayingSid + '"]');
    if (oldBtn) resetTtsBtn(oldBtn);
    ttsPlayingSid = null;
  }
  ttsPlayAllMode = wasPlayAll;

  var step = state.steps.find(function(s) { return s.id === sid; });
  if (!step) return;

  // Build text to speak: title + description
  var text = "";
  if (step.title) text += step.title + ". ";
  if (step.description) text += step.description;
  text = text.trim();

  if (!text) {
    showToast("No text to speak — add a title or description first");
    return;
  }

  ttsPlayingSid = sid;
  btn.textContent = "\u23f3 Loading...";
  btn.style.background = "rgba(59,130,246,0.15)";
  btn.style.color = "#60a5fa";
  btn.style.borderColor = "rgba(59,130,246,0.3)";

  // Check cache first
  if (ttsAudioCache[sid + "_" + text]) {
    playTtsAudio(ttsAudioCache[sid + "_" + text], sid, btn);
    return;
  }

  // Call background for TTS
  var selectedVoice = document.getElementById("ttsVoiceSelect").value || "nova";
  chrome.runtime.sendMessage({
    action: "TTS_SPEAK",
    text: text,
    voice: selectedVoice
  }, function(res) {
    if (chrome.runtime.lastError) {
      showToast("TTS error: " + chrome.runtime.lastError.message);
      resetTtsBtn(btn);
      ttsPlayingSid = null;
      return;
    }
    if (res && res.success && res.audioDataUrl) {
      // Cache it
      ttsAudioCache[sid + "_" + text] = res.audioDataUrl;
      playTtsAudio(res.audioDataUrl, sid, btn);
    } else {
      showToast(res ? res.error : "TTS failed");
      resetTtsBtn(btn);
      ttsPlayingSid = null;
    }
  });
}

function playTtsAudio(audioDataUrl, sid, btn) {
  ttsAudio = new Audio(audioDataUrl);
  ttsPlayingSid = sid;

  btn.textContent = "\u23f9 Stop";
  btn.style.background = "rgba(239,68,68,0.15)";
  btn.style.color = "#f87171";
  btn.style.borderColor = "rgba(239,68,68,0.3)";

  ttsAudio.onended = function() {
    resetTtsBtn(btn);
    ttsPlayingSid = null;
    ttsAudio = null;

    // If Play All mode, play next step
    if (ttsPlayAllMode) {
      ttsPlayAllIndex++;
      ttsPlayNext();
    }
  };

  ttsAudio.onerror = function() {
    showToast("Audio playback error");
    resetTtsBtn(btn);
    ttsPlayingSid = null;
    ttsAudio = null;
    ttsPlayAllMode = false;
  };

  ttsAudio.play().catch(function(e) {
    showToast("Playback failed: " + e.message);
    resetTtsBtn(btn);
    ttsPlayingSid = null;
    ttsAudio = null;
  });
}

function ttsStop() {
  ttsPlayAllMode = false;
  if (ttsAudio) {
    ttsAudio.pause();
    ttsAudio.currentTime = 0;
    ttsAudio = null;
  }
  // Reset any active play buttons
  if (ttsPlayingSid) {
    var activeBtn = document.querySelector('.tts-play[data-sid="' + ttsPlayingSid + '"]');
    if (activeBtn) resetTtsBtn(activeBtn);
    ttsPlayingSid = null;
  }
  // Reset Play All button
  var playAllBtn = document.getElementById("ttsPlayAllBtn");
  if (playAllBtn) {
    playAllBtn.innerHTML = '\u25b6\ufe0f Play All Steps';
    playAllBtn.style.background = "";
    playAllBtn.style.color = "";
    playAllBtn.style.borderColor = "";
  }
}

function ttsPlayAll() {
  if (ttsPlayAllMode) {
    ttsStop();
    return;
  }
  if (state.steps.length === 0) {
    showToast("No steps to play");
    return;
  }

  ttsPlayAllMode = true;
  ttsPlayAllIndex = 0;

  var playAllBtn = document.getElementById("ttsPlayAllBtn");
  if (playAllBtn) {
    playAllBtn.innerHTML = '\u23f9 Stop Playing';
    playAllBtn.style.background = "rgba(239,68,68,0.15)";
    playAllBtn.style.color = "#f87171";
    playAllBtn.style.borderColor = "rgba(239,68,68,0.3)";
  }

  ttsPlayNext();
}

function ttsPlayNext() {
  if (!ttsPlayAllMode) return;
  if (ttsPlayAllIndex >= state.steps.length) {
    ttsPlayAllMode = false;
    showToast("Finished playing all steps");
    var playAllBtn = document.getElementById("ttsPlayAllBtn");
    if (playAllBtn) {
      playAllBtn.innerHTML = '\u25b6\ufe0f Play All Steps';
      playAllBtn.style.background = "";
      playAllBtn.style.color = "";
      playAllBtn.style.borderColor = "";
    }
    return;
  }

  var step = state.steps[ttsPlayAllIndex];
  selectStep(step.id);

  // Find the play button for this step
  var btn = document.querySelector('.tts-play[data-sid="' + step.id + '"]');
  if (!btn) {
    // Step might not be rendered yet after selectStep re-render
    setTimeout(function() {
      btn = document.querySelector('.tts-play[data-sid="' + step.id + '"]');
      if (btn) {
        ttsPlayStep(step.id, btn);
      } else {
        ttsPlayAllIndex++;
        ttsPlayNext();
      }
    }, 100);
    return;
  }

  ttsPlayStep(step.id, btn);
}

function resetTtsBtn(btn) {
  if (!btn) return;
  btn.textContent = "\ud83d\udd0a Play";
  btn.style.background = "";
  btn.style.color = "";
  btn.style.borderColor = "";
}

// ============================================================
// AUTO-GENERATE TITLE & DESCRIPTION
// ============================================================

function autoGenerateTitle() {
  if (state.steps.length === 0) { showToast("Add some steps first"); return; }

  // Collect info from all steps
  var urls = [];
  var actions = [];
  var domains = [];

  state.steps.forEach(function(step) {
    // Collect domains
    if (step.url) {
      var h = hostname(step.url);
      if (h && domains.indexOf(h) === -1) domains.push(h);
    }

    // Collect meaningful action words from step titles
    var title = step.title || "";
    if (title) actions.push(title);
  });

  // --- Generate Title ---
  var docTitle = "";
  var docSubtitle = "";

  // Look at the primary domain and first/last actions
  var mainDomain = domains.length > 0 ? domains[0] : "";
  var firstAction = actions.length > 0 ? actions[0] : "";
  var lastAction = actions.length > 1 ? actions[actions.length - 1] : "";

  // Try to find the "what" from the page titles
  var pageTitles = state.steps.map(function(s) { return s.pageTitle || ""; }).filter(Boolean);
  var mainPageTitle = pageTitles.length > 0 ? pageTitles[0] : "";

  // Build a smart title
  if (mainPageTitle) {
    // Extract meaningful part from page title (before | or - or :)
    var cleanPageTitle = mainPageTitle.split(/[\|\-\:—]/)[0].trim();
    if (cleanPageTitle.length > 5 && cleanPageTitle.length < 60) {
      docTitle = "How to Use " + cleanPageTitle;
    }
  }

  if (!docTitle && mainDomain) {
    // Prettify domain name
    var domainName = mainDomain.replace(/^www\./, "").split(".")[0];
    domainName = domainName.charAt(0).toUpperCase() + domainName.slice(1);

    if (actions.length > 0) {
      // Extract verb + object from first meaningful action
      var actionVerb = extractMainAction(actions);
      if (actionVerb) {
        docTitle = "How to " + actionVerb + " on " + domainName;
      } else {
        docTitle = "How to Use " + domainName;
      }
    } else {
      docTitle = domainName + " — Step-by-Step Guide";
    }
  }

  if (!docTitle) {
    docTitle = "Step-by-Step Guide (" + state.steps.length + " Steps)";
  }

  // --- Generate Description ---
  var stepSummary = state.steps.length + " step" + (state.steps.length !== 1 ? "s" : "");

  if (domains.length === 1) {
    docSubtitle = "A " + stepSummary + " guide covering the workflow on " + domains[0] + ".";
  } else if (domains.length > 1) {
    docSubtitle = "A " + stepSummary + " guide covering " + domains.slice(0, 3).join(", ") + (domains.length > 3 ? " and more" : "") + ".";
  } else {
    docSubtitle = "A " + stepSummary + " walkthrough with screenshots and annotations.";
  }

  // Set values
  document.getElementById("docTitle").value = docTitle;
  document.getElementById("docSubtitle").value = docSubtitle;
  showToast("Title and description generated!");
}

function extractMainAction(actions) {
  // Look through step titles for meaningful verbs
  var keywords = [];
  var verbs = {
    "click": true, "navigate": true, "open": true, "select": true, "enter": true,
    "configure": true, "setup": true, "create": true, "add": true, "edit": true,
    "update": true, "delete": true, "save": true, "submit": true, "upload": true,
    "download": true, "install": true, "connect": true, "manage": true, "set": true
  };

  for (var i = 0; i < actions.length; i++) {
    var words = actions[i].toLowerCase().replace(/["']/g, "").split(/\s+/);
    // Find the object of the click (what they're clicking on)
    if (words[0] === "click" && words.length >= 2) {
      var obj = words.slice(1).join(" ").replace(/^(the|on|a|an)\s+/i, "");
      if (obj.length > 2 && obj.length < 40) {
        keywords.push(obj);
      }
    }
  }

  // Find the most interesting/unique actions
  if (keywords.length >= 2) {
    // Use first and last meaningful action
    return capitalize(keywords[0]) + " and " + capitalize(keywords[keywords.length - 1]);
  } else if (keywords.length === 1) {
    return capitalize(keywords[0]);
  }

  return null;
}

function capitalize(str) {
  if (!str) return "";
  return str.charAt(0).toUpperCase() + str.slice(1);
}

// ============================================================
// BRAND SETTINGS PERSISTENCE
// ============================================================

function saveBrandSettings() {
  updateBrand(); // Update state first

  if (typeof chrome === "undefined" || !chrome.storage) return;

  var brandData = {
    name: state.brand.name,
    primaryColor: state.brand.primaryColor,
    accentColor: state.brand.accentColor,
    logo: state.brand.logo
  };

  chrome.storage.local.set({ savedBrandSettings: brandData }, function() {
    console.log("Brand settings saved");
  });
}

function applyBrandToUI() {
  document.getElementById("brandName").value = state.brand.name;
  document.getElementById("brandColor").value = state.brand.primaryColor;
  document.getElementById("brandColorHex").value = state.brand.primaryColor;
  document.getElementById("accentColor").value = state.brand.accentColor;
  document.getElementById("accentColorHex").value = state.brand.accentColor;
  if (state.brand.logo) {
    document.getElementById("logoPreview").innerHTML = '<img src="' + state.brand.logo + '"><div class="upload-text">Click to change</div>';
  }
}

function loadBrandSettings() {
  if (typeof chrome === "undefined" || !chrome.storage) {
    // No chrome storage — still apply hardcoded defaults to UI
    applyBrandToUI();
    return;
  }

  chrome.storage.local.get(["savedBrandSettings"], function(result) {
    if (!result.savedBrandSettings) {
      // No saved brand — apply hardcoded defaults to UI
      applyBrandToUI();
      return;
    }

    var brand = result.savedBrandSettings;

    if (brand.name) {
      state.brand.name = brand.name;
      document.getElementById("brandName").value = brand.name;
    }
    if (brand.primaryColor) {
      state.brand.primaryColor = brand.primaryColor;
      document.getElementById("brandColor").value = brand.primaryColor;
      document.getElementById("brandColorHex").value = brand.primaryColor;
    }
    if (brand.accentColor) {
      state.brand.accentColor = brand.accentColor;
      document.getElementById("accentColor").value = brand.accentColor;
      document.getElementById("accentColorHex").value = brand.accentColor;
    }
    if (brand.logo) {
      state.brand.logo = brand.logo;
      document.getElementById("logoPreview").innerHTML = '<img src="' + brand.logo + '"><div class="upload-text">Click to change</div>';
    }

    console.log("Brand settings loaded");
  });
}

function handleLogoUpload(e) {
  var f = e.target.files[0]; if (!f) return;
  var r = new FileReader();
  r.onload = function(ev) {
    state.brand.logo = ev.target.result;
    document.getElementById("logoPreview").innerHTML = '<img src="' + ev.target.result + '"><div class="upload-text">Click to change</div>';
    saveBrandSettings(); // Auto-save brand when logo changes
  };
  r.readAsDataURL(f);
}

