// IMPORT / EXPORT
// ============================================================

// ============================================================
// PROJECT SAVE / LOAD (File System Access API)
// ============================================================

async function saveProject() {
  try {
    var handle = await window.showSaveFilePicker({
      suggestedName: slug(document.getElementById("docTitle").value || "my-project") + ".stepwise",
      types: [{
        description: "StepWise Project",
        accept: { "application/json": [".stepwise"] }
      }]
    });

    projectFileHandle = handle;
    await writeProjectToHandle(handle);
    updateProjectInfo(handle.name);
    showToast("Project saved!");

  } catch(err) {
    if (err.name !== "AbortError") {
      console.error("Save error:", err);
      showToast("Save failed: " + err.message);
    }
  }
}

async function quickSaveProject() {
  if (!projectFileHandle) { saveProject(); return; }
  try {
    await writeProjectToHandle(projectFileHandle);
    updateProjectInfo(projectFileHandle.name);
    showToast("Saved!");
  } catch(err) {
    console.error("Quick save error:", err);
    // Permission might have been revoked — ask again
    saveProject();
  }
}

async function writeProjectToHandle(handle) {
  var projectData = {
    format: "stepwise-project",
    version: "1.1",
    title: document.getElementById("docTitle").value || "",
    subtitle: document.getElementById("docSubtitle").value || "",
    brand: state.brand,
    steps: state.steps,
    savedAt: new Date().toISOString()
  };

  var writable = await handle.createWritable();
  await writable.write(JSON.stringify(projectData));
  await writable.close();
}

async function loadProject() {
  try {
    var handles = await window.showOpenFilePicker({
      types: [{
        description: "StepWise Project",
        accept: { "application/json": [".stepwise", ".json"] }
      }],
      multiple: false
    });

    var handle = handles[0];
    var file = await handle.getFile();
    var text = await file.text();
    var data = JSON.parse(text);

    // Accept both project format and plain JSON export
    if (data.format === "stepwise-project" || data.steps) {
      state.steps = data.steps || [];
      state.steps.forEach(function(s) { if (!s.annotations) s.annotations = []; });

      if (data.title) document.getElementById("docTitle").value = data.title;
      if (data.subtitle) document.getElementById("docSubtitle").value = data.subtitle;

      if (data.brand) {
        state.brand.name = data.brand.name || state.brand.name;
        state.brand.primaryColor = data.brand.primaryColor || state.brand.primaryColor;
        state.brand.accentColor = data.brand.accentColor || state.brand.accentColor;
        if (data.brand.logo) state.brand.logo = data.brand.logo;
        document.getElementById("brandName").value = state.brand.name || DEFAULT_BRAND_NAME;
        document.getElementById("brandColor").value = data.brand.primaryColor || "#3b82f6";
        document.getElementById("brandColorHex").value = data.brand.primaryColor || "#3b82f6";
        document.getElementById("accentColor").value = data.brand.accentColor || "#8b5cf6";
        document.getElementById("accentColorHex").value = data.brand.accentColor || "#8b5cf6";
        if (data.brand.logo) {
          document.getElementById("logoPreview").innerHTML = '<img src="' + data.brand.logo + '"><div class="upload-text">Click to change</div>';
        }
      }

      state.activeStepId = state.steps.length > 0 ? state.steps[0].id : null;
      lastKnownStepCount = state.steps.length;

      // Store handle for quick save
      projectFileHandle = handle;
      updateProjectInfo(handle.name);

      showEditor(); render();
      showToast("Loaded " + state.steps.length + " steps from " + handle.name);
    } else {
      showToast("Invalid project file");
    }

  } catch(err) {
    if (err.name !== "AbortError") {
      console.error("Load error:", err);
      showToast("Load failed: " + err.message);
    }
  }
}

function updateProjectInfo(fileName) {
  var infoDiv = document.getElementById("projectInfo");
  var quickBtn = document.getElementById("saveQuickBtn");
  document.getElementById("projectFileName").textContent = "📄 " + fileName;
  document.getElementById("projectSavedAt").textContent = "Saved " + new Date().toLocaleTimeString();
  infoDiv.style.display = "block";
  quickBtn.style.display = "block";
}

// ============================================================
// CONTINUE RECORDING FROM EDITOR
// ============================================================

function editorStartRecording() {
  if (typeof chrome === "undefined" || !chrome.runtime) {
    showToast("Recording only works in the Chrome extension");
    return;
  }

  // First, push current editor steps TO the background so numbering continues
  chrome.runtime.sendMessage({ action: "GET_STEPS" }, function(res) {
    if (chrome.runtime.lastError) return;

    // If background has fewer steps than editor (e.g. we loaded from file),
    // we need to sync. Send START then immediately the existing steps count.
    var bgCount = (res && res.steps) ? res.steps.length : 0;

    var action = bgCount > 0 ? "CONTINUE_RECORDING" : "START_RECORDING";

    // If starting fresh but we have editor steps, use continue
    if (state.steps.length > 0) action = "CONTINUE_RECORDING";

    chrome.runtime.sendMessage({ action: action }, function(startRes) {
      if (chrome.runtime.lastError) return;
      editorRecording = true;
      lastKnownStepCount = (startRes && startRes.stepCount) || 0;
      updateRecordingUI();
      startRecordingPoll();
      showToast("Recording started! Switch to another tab and click around.");
    });
  });
}

function editorStopRecording() {
  if (typeof chrome === "undefined" || !chrome.runtime) return;

  chrome.runtime.sendMessage({ action: "STOP_RECORDING" }, function(res) {
    if (chrome.runtime.lastError) return;
    editorRecording = false;
    stopRecordingPoll();
    updateRecordingUI();

    // Pull in any final steps
    pullNewSteps();
    showToast("Recording stopped!");
  });
}

function updateRecordingUI() {
  var continueBtn = document.getElementById("editorContinueRecBtn");
  var stopBtn = document.getElementById("editorStopRecBtn");
  var continueBtn2 = document.getElementById("editorContinueRecBtn2");
  var stopBtn2 = document.getElementById("editorStopRecBtn2");
  var recStatus = document.getElementById("recStatus");

  if (editorRecording) {
    continueBtn.style.display = "none";
    stopBtn.style.display = "flex";
    continueBtn2.style.display = "none";
    stopBtn2.style.display = "flex";
    recStatus.style.display = "block";
  } else {
    continueBtn.style.display = "flex";
    stopBtn.style.display = "none";
    continueBtn2.style.display = "flex";
    stopBtn2.style.display = "none";
    recStatus.style.display = "none";
  }
}

function startRecordingPoll() {
  stopRecordingPoll(); // Clear any existing
  recPollInterval = setInterval(pullNewSteps, 1000); // Check every second
}

function stopRecordingPoll() {
  if (recPollInterval) { clearInterval(recPollInterval); recPollInterval = null; }
}

function pullNewSteps() {
  if (typeof chrome === "undefined" || !chrome.runtime) return;

  chrome.runtime.sendMessage({ action: "GET_STEPS" }, function(res) {
    if (chrome.runtime.lastError) return;
    if (!res || !res.steps) return;

    var bgSteps = res.steps;

    if (bgSteps.length > lastKnownStepCount) {
      // New steps captured! Append ones we don't have
      var newSteps = bgSteps.slice(lastKnownStepCount);
      newSteps.forEach(function(s) {
        if (!s.annotations) s.annotations = [];
        // Check not already in editor
        var exists = state.steps.find(function(es) { return es.id === s.id; });
        if (!exists) {
          state.steps.push(s);
        }
      });

      lastKnownStepCount = bgSteps.length;
      state.activeStepId = state.steps[state.steps.length - 1].id;
      showEditor(); render();

      // Scroll to newest step
      var el = document.getElementById("editor-" + state.activeStepId);
      if (el) el.scrollIntoView({ behavior: "smooth", block: "center" });
    }
  });
}

