async function shareDoc() {
  var btn = document.getElementById("shareBtn");
  var resultDiv = document.getElementById("shareResult");
  var urlInput = document.getElementById("shareUrlInput");

  if (!PUBLISH_SECRET) {
    // Try loading from chrome.storage
    if (typeof chrome !== "undefined" && chrome.storage) {
      var result = await new Promise(function(resolve) { chrome.storage.local.get(["publishSecret"], resolve); });
      if (result.publishSecret) {
        PUBLISH_SECRET = result.publishSecret;
      } else {
        var key = prompt("Enter your Publish API secret key:\n(From your VPS setup — you only need to do this once)");
        if (!key) return;
        PUBLISH_SECRET = key.trim();
        chrome.storage.local.set({ publishSecret: PUBLISH_SECRET });
      }
    } else {
      showToast("Set PUBLISH_SECRET in editor.js");
      return;
    }
  }

  if (state.steps.length === 0) {
    showToast("No steps to publish");
    return;
  }

  btn.disabled = true;
  btn.textContent = "⏳ Publishing...";

  try {
    var html = await generateHTMLContent();
    var title = document.getElementById("docTitle").value || "Untitled Guide";

    var response = await fetch(PUBLISH_API_URL + "/publish", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": "Bearer " + PUBLISH_SECRET
      },
      body: JSON.stringify({
        html: html,
        title: title
      })
    });

    var data = await response.json();

    if (!response.ok || !data.success) {
      throw new Error(data.error || "Publish failed");
    }

    urlInput.value = data.url;
    resultDiv.style.display = "block";
    btn.textContent = "🌐 Publish — Get Link";
    btn.disabled = false;
    showToast("Published! Link is permanent.");

    // Save to publish history
    saveShareLink({
      url: data.url,
      title: title,
      steps: state.steps.length,
      slug: data.slug,
      createdAt: new Date().toISOString()
    });

  } catch(err) {
    btn.textContent = "🌐 Publish — Get Link";
    btn.disabled = false;
    resultDiv.style.display = "none";
    showToast("Publish failed: " + err.message);
    console.error("Publish error:", err);
  }
}

// ============================================================
// SHARE HISTORY
// ============================================================

function saveShareLink(entry) {
  if (typeof chrome === "undefined" || !chrome.storage) return;
  chrome.storage.local.get(["shareHistory"], function(result) {
    var history = result.shareHistory || [];
    history.unshift(entry); // Newest first
    if (history.length > 50) history = history.slice(0, 50); // Keep last 50
    chrome.storage.local.set({ shareHistory: history }, function() {
      renderShareHistory(history);
    });
  });
}

function loadShareHistory() {
  if (typeof chrome === "undefined" || !chrome.storage) return;
  chrome.storage.local.get(["shareHistory"], function(result) {
    var history = result.shareHistory || [];
    renderShareHistory(history);
  });
}

function renderShareHistory(history) {
  var container = document.getElementById("shareHistory");
  if (!container) return;
  if (!history || history.length === 0) {
    container.innerHTML = "";
    return;
  }

  var html = '<div style="font-size:10px;font-weight:600;text-transform:uppercase;letter-spacing:0.05em;color:var(--text-3);margin-bottom:6px;">Published Guides</div>';
  history.forEach(function(entry, idx) {
    var dateStr = new Date(entry.createdAt).toLocaleDateString();
    html += '<div style="display:flex;align-items:center;gap:6px;padding:5px 0;border-bottom:1px solid var(--border);font-size:11px;">' +
      '<div style="flex:1;min-width:0;">' +
        '<div style="font-weight:500;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + esc(entry.title) + '</div>' +
        '<div style="color:var(--text-3);font-size:9px;">' + entry.steps + ' steps · ' + dateStr + '</div>' +
      '</div>' +
      '<button class="sa-btn copy-history-link" data-url="' + escAttr(entry.url) + '" title="Copy link" style="font-size:11px;width:auto;padding:2px 6px;">📋</button>' +
      '<a href="' + escAttr(entry.url) + '" target="_blank" class="sa-btn" title="Open" style="font-size:11px;width:auto;padding:2px 6px;text-decoration:none;color:var(--text-2);">↗</a>' +
      '<button class="sa-btn delete-guide-btn" data-slug="' + escAttr(entry.slug || "") + '" data-idx="' + idx + '" title="Delete" style="font-size:11px;width:auto;padding:2px 6px;color:#ef4444;">🗑️</button>' +
    '</div>';
  });

  container.innerHTML = html;

  // Attach copy listeners
  container.querySelectorAll(".copy-history-link").forEach(function(btn) {
    btn.addEventListener("click", function() {
      navigator.clipboard.writeText(btn.dataset.url).then(function() { showToast("Link copied!"); });
    });
  });

  // Attach delete listeners
  container.querySelectorAll(".delete-guide-btn").forEach(function(btn) {
    btn.addEventListener("click", function() {
      var slug = btn.dataset.slug;
      var idx = parseInt(btn.dataset.idx);
      // If no slug, try to extract from URL
      if (!slug) {
        var url = btn.closest("div").querySelector(".copy-history-link");
        if (url) {
          var parts = url.dataset.url.split("/");
          slug = parts[parts.length - 1].replace(".html", "");
        }
      }
      if (!slug) { showToast("Cannot delete — no guide info"); return; }
      if (!confirm("Delete this guide permanently?\nThis removes it from the server.")) return;
      deletePublishedGuide(slug, idx);
    });
  });
}

async function deletePublishedGuide(slug, idx) {
  if (!PUBLISH_SECRET) {
    if (typeof chrome !== "undefined" && chrome.storage) {
      var result = await new Promise(function(resolve) { chrome.storage.local.get(["publishSecret"], resolve); });
      PUBLISH_SECRET = result.publishSecret || "";
    }
  }
  if (!PUBLISH_SECRET) { showToast("No publish secret key set"); return; }

  try {
    var response = await fetch(PUBLISH_API_URL + "/delete/" + slug, {
      method: "DELETE",
      headers: { "Authorization": "Bearer " + PUBLISH_SECRET }
    });
    var data = await response.json();
    if (!response.ok || !data.success) {
      throw new Error(data.error || "Delete failed");
    }

    // Remove from local history
    if (typeof chrome !== "undefined" && chrome.storage) {
      chrome.storage.local.get(["shareHistory"], function(result) {
        var history = result.shareHistory || [];
        history.splice(idx, 1);
        chrome.storage.local.set({ shareHistory: history }, function() {
          renderShareHistory(history);
        });
      });
    }
    showToast("Guide deleted!");
  } catch(err) {
    showToast("Delete failed: " + err.message);
    console.error("Delete error:", err);
  }
}

