function showEditor() { document.getElementById("importArea").style.display = "none"; document.getElementById("editorArea").style.display = "block"; }
function showToast(m) { var t = document.getElementById("toast"); t.textContent = m; t.classList.add("show"); setTimeout(function() { t.classList.remove("show"); }, 2500); }
function esc(s) { var d = document.createElement("div"); d.textContent = s || ""; return d.innerHTML; }
function escAttr(s) { return (s || "").replace(/&/g, "&amp;").replace(/"/g, "&quot;").replace(/</g, "&lt;"); }
function slug(s) { return (s || "doc").toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "").substring(0, 50); }
function hostname(u) { try { return new URL(u).hostname; } catch(e) { return ""; } }
function dlFile(c, f, m) { var b = new Blob([c], { type: m }); var u = URL.createObjectURL(b); var a = document.createElement("a"); a.href = u; a.download = f; document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(u); }

// ============================================================
// VIDEO GENERATION
// ============================================================

var videoJobId = null;
var videoPollTimer = null;
var videoCancelled = false;

function startVideoGeneration() {
  if (!state.steps || state.steps.length === 0) {
    showToast("No steps to generate video from");
    return;
  }

  // Check if steps have descriptions
  var stepsWithDesc = state.steps.filter(function(s) { return s.description && s.description.trim().length > 0; });
  if (stepsWithDesc.length === 0) {
    showToast("Add descriptions to your steps first (the voice will read them)");
    return;
  }

  // Get API key via background.js (which has the working decrypt)
  chrome.runtime.sendMessage({ action: "GET_API_KEY" }, function(result) {
    if (chrome.runtime.lastError || !result || !result.success) {
      showToast("Set up your OpenAI API key in Settings first");
      return;
    }

    var apiKey = result.apiKey;
    if (!apiKey || apiKey.length < 10) {
      showToast("Invalid API key. Check Settings.");
      return;
    }

    // Show modal early so user sees progress
    videoCancelled = false;
    var modal = document.getElementById("videoModal");
    modal.classList.add("active");
    document.getElementById("videoProgressFill").style.width = "0%";
    document.getElementById("videoStatusText").textContent = "Preparing annotated screenshots...";
    document.getElementById("videoModalTitle").textContent = "\ud83c\udfac Generating Video...";
    document.getElementById("videoModalMsg").textContent = "This may take a minute. Don\u2019t close this tab.";
    document.getElementById("videoCancelBtn").textContent = "Cancel";
    document.getElementById("videoCancelBtn").style.display = "inline-block";

    // Disable button
    var btn = document.getElementById("generateVideoBtn");
    btn.disabled = true;
    btn.textContent = "\u23f3 Generating...";

    // Merge annotations onto screenshots (so edits appear in video!)
    var mergePromises = state.steps.map(function(step) {
      return getMergedImage(step);
    });

    Promise.all(mergePromises).then(function(mergedImages) {

    // Prepare steps data with merged (annotated) screenshots
    var stepsData = state.steps.map(function(step, idx) {
      return {
        title: step.title || "",
        description: step.description || "",
        screenshot: mergedImages[idx] || step.screenshot || ""
      };
    });

    var selectedVoice = document.getElementById("ttsVoiceSelect").value || "nova";

    document.getElementById("videoStatusText").textContent = "Sending data to server...";

    // Built-in VPS URL
    var vpsUrl = "http://109.205.182.135:3500";

    fetch(vpsUrl + "/generate-video", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        projectTitle: document.getElementById("docTitle").value || "StepWise Documentation",
        projectDescription: document.getElementById("docSubtitle").value || "",
        steps: stepsData,
        voice: selectedVoice,
        apiKey: apiKey
      })
    })
    .then(function(res) { return res.json(); })
    .then(function(data) {
      if (data.error) {
        videoError(data.error);
        return;
      }
      videoJobId = data.jobId;
      // Start polling for progress
      pollVideoProgress(vpsUrl, videoJobId);
    })
    .catch(function(err) {
      videoError("Could not connect to video server: " + err.message);
    });

    }); // end Promise.all(mergePromises).then()
  }); // end chrome.runtime.sendMessage
} // end startVideoGeneration

function pollVideoProgress(vpsUrl, jobId) {
  if (videoCancelled) return;

  fetch(vpsUrl + "/status/" + jobId)
  .then(function(res) { return res.json(); })
  .then(function(data) {
    if (videoCancelled) return;

    if (data.status === "processing") {
      document.getElementById("videoProgressFill").style.width = data.progress + "%";
      document.getElementById("videoStatusText").textContent = data.message || "Processing...";

      // Poll again in 2 seconds
      videoPollTimer = setTimeout(function() {
        pollVideoProgress(vpsUrl, jobId);
      }, 2000);

    } else if (data.status === "done") {
      document.getElementById("videoProgressFill").style.width = "100%";
      document.getElementById("videoStatusText").textContent = "Video ready!";
      document.getElementById("videoModalTitle").textContent = "\u2705 Video Ready!";
      document.getElementById("videoCancelBtn").textContent = "Close";

      // Download the video file to their computer (no auto-close after)
      downloadVideoNoClose(vpsUrl, jobId, data.fileName || "stepwise-video.mp4");

      // Show GHL status — keep modal open until user sees the link
      if (data.ghlUrl) {
        showGHLLink(data.ghlUrl);
      } else if (data.ghlError) {
        document.getElementById("videoModalMsg").innerHTML = "\u2705 Video downloaded to your computer.<br><br>\u26a0\ufe0f GHL upload issue: " + data.ghlError;
      } else {
        document.getElementById("videoModalMsg").innerHTML = "\u2705 Video downloaded to your computer.<br><br>\u23f3 Saving to GoHighLevel... please wait...";
        // Poll for GHL URL — keep trying for up to 60 seconds
        pollGHLStatus(vpsUrl, jobId, 0);
      }

    } else if (data.status === "error") {
      videoError(data.message || "Video generation failed");
    }
  })
  .catch(function(err) {
    if (!videoCancelled) {
      videoError("Lost connection to server: " + err.message);
    }
  });
}

function downloadVideoNoClose(vpsUrl, jobId, fileName) {
  fetch(vpsUrl + "/download/" + jobId)
  .then(function(res) {
    if (!res.ok) throw new Error("Download failed");
    return res.blob();
  })
  .then(function(blob) {
    var url = URL.createObjectURL(blob);
    var a = document.createElement("a");
    a.href = url;
    a.download = fileName;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    showToast("Video downloaded to your computer!");
    // Do NOT close modal — keep it open for GHL link
    // Just reset the button so they can generate another later
    var btn = document.getElementById("generateVideoBtn");
    btn.disabled = false;
    btn.textContent = "\ud83c\udfac Generate MP4 Video";
  })
  .catch(function(err) {
    showToast("Download failed: " + err.message);
  });
}

// Show the GHL link with a Copy button
function showGHLLink(ghlUrl) {
  document.getElementById("videoModalMsg").innerHTML = 
    "\u2705 Video downloaded to your computer.<br><br>" +
    "\u2705 <b>Saved to GoHighLevel!</b><br><br>" +
    "<div style='background:#f0f0ff;border:1px solid #c7c7f7;border-radius:8px;padding:10px;margin:6px 0;word-break:break-all;font-size:12px;'>" +
    "<a href='" + ghlUrl + "' target='_blank' style='color:#6366f1;'>" + ghlUrl + "</a></div>" +
    "<button onclick=\"navigator.clipboard.writeText('" + ghlUrl + "');this.textContent='\u2705 Copied!';setTimeout(function(){document.querySelector('#videoModalMsg button').textContent='\ud83d\udccb Copy Link'},2000)\" " +
    "style='margin-top:8px;padding:8px 20px;background:#6366f1;color:white;border:none;border-radius:6px;cursor:pointer;font-size:14px;'>" +
    "\ud83d\udccb Copy Link</button>";
}

// Poll for GHL URL — retries every 5 seconds, up to 12 tries (60 seconds)
function pollGHLStatus(vpsUrl, jobId, attempt) {
  if (attempt >= 12) {
    document.getElementById("videoModalMsg").innerHTML = 
      "\u2705 Video downloaded to your computer.<br><br>" +
      "\u26a0\ufe0f GHL upload is taking longer than expected.<br>" +
      "Check your GoHighLevel media library in a minute.";
    return;
  }

  setTimeout(function() {
    fetch(vpsUrl + "/status/" + jobId)
    .then(function(res) { return res.json(); })
    .then(function(data) {
      if (data.ghlUrl) {
        showGHLLink(data.ghlUrl);
      } else if (data.ghlError) {
        document.getElementById("videoModalMsg").innerHTML = 
          "\u2705 Video downloaded to your computer.<br><br>" +
          "\u26a0\ufe0f GHL upload issue: " + data.ghlError;
      } else {
        // Still waiting — try again
        pollGHLStatus(vpsUrl, jobId, attempt + 1);
      }
    }).catch(function() {
      // Network error — try again
      pollGHLStatus(vpsUrl, jobId, attempt + 1);
    });
  }, 5000);
}

function cancelVideoGeneration() {
  videoCancelled = true;
  if (videoPollTimer) {
    clearTimeout(videoPollTimer);
    videoPollTimer = null;
  }
  resetVideoUI();
}

function videoError(msg) {
  document.getElementById("videoModalTitle").textContent = "\u274c Error";
  document.getElementById("videoStatusText").textContent = msg;
  document.getElementById("videoModalMsg").textContent = "Check your OpenAI API key in Settings and try again.";
  document.getElementById("videoCancelBtn").textContent = "Close";
  document.getElementById("videoProgressFill").style.width = "0%";

  // Reset button
  var btn = document.getElementById("generateVideoBtn");
  btn.disabled = false;
  btn.textContent = "\ud83c\udfac Generate MP4 Video";
}

function resetVideoUI() {
  document.getElementById("videoModal").classList.remove("active");
  var btn = document.getElementById("generateVideoBtn");
  btn.disabled = false;
  btn.textContent = "\ud83c\udfac Generate MP4 Video";
}

